def missing_source_session_rows(state: State, existing_keys: set[str]) -> tuple[list[tuple[str, float, str, int, str]], bool]:
    names: dict[str, str] = {}
    if session_names is not None:
        try:
            names = session_names._load()
        except Exception:
            names = {}
    candidates = {
        key
        for key in [*state.session_meta.keys(), *names.keys()]
        if is_model_response_basename(str(key))
    }
    rows: list[tuple[str, float, str, int, str]] = []
    changed = False
    for key in sorted(candidates):
        if key in existing_keys:
            continue
        path = os.path.join(MODEL_RESPONSES_DIR, key)
        if os.path.exists(path):
            continue
        meta = dict(state.session_meta.get(key, {}))
        if bool(meta.get("deleted")) or bool(meta.get("hidden_subagent_log")):
            continue
        title = compact_title(str(names.get(key) or ""), 80)
        desc = compact_description(str(meta.get("description") or title or ""))
        preview = str(meta.get("preview") or desc or title or "已登记的历史会话").strip()
        last_user_at = max(
            session_meta_epoch(meta.get("last_user_at")),
            session_meta_epoch(meta.get("last_opened_at")),
            session_meta_epoch(meta.get("cache_mtime")),
            session_meta_epoch(meta.get("updated_at")),
        )
        try:
            rounds = int(meta.get("rounds") or meta.get("ui_preview_total_rounds") or 0)
        except (TypeError, ValueError):
            rounds = 0
        entry = dict(meta)
        entry.update({
            "source_missing": True,
            "archive_backed": True,
            "source_state": "missing",
            "source_path": path,
            "original_basename": key,
        })
        if preview and not entry.get("preview"):
            entry["preview"] = preview
        if desc and not entry.get("description"):
            entry["description"] = desc
        if last_user_at and not entry.get("last_user_at"):
            entry["last_user_at"] = last_user_at
        if rounds and not entry.get("rounds"):
            entry["rounds"] = rounds
        if entry != meta:
            state.session_meta[key] = entry
            changed = True
        rows.append((path, last_user_at, preview, rounds, desc))
    return rows, changed


def cached_session_rows(state: State, exclude_pid: Optional[int] = None) -> tuple[list[tuple[str, float, str, int, str]], bool]:
    tag = f"model_responses_{exclude_pid}.txt" if exclude_pid is not None else ""
    paths = sorted(glob.glob(os.path.join(MODEL_RESPONSES_DIR, "model_responses*.txt")), key=os.path.getmtime, reverse=True)
    rows: list[tuple[str, float, str, int, str]] = []
    changed = False
    existing_keys: set[str] = set()
    for path in paths:
        if tag and path.endswith(tag):
            continue
        key = session_key(path)
        existing_keys.add(key)
        try:
            stat = os.stat(path)
        except OSError:
            continue
        meta = state.session_meta.get(key, {})
        cleaned_meta, cleaned = clear_missing_source_session_meta(meta)
        if cleaned:
            state.session_meta[key] = cleaned_meta
            meta = cleaned_meta
            changed = True
        if bool(meta.get("hidden_subagent_log")):
            continue
        if is_subagent_session_log_sample(sample_file_text(path)):
            entry = dict(meta)
            entry["hidden_subagent_log"] = True
            entry["cache_mtime"] = stat.st_mtime
            entry["cache_size"] = stat.st_size
            entry["preview"] = "subagent session log"
            entry["rounds"] = 0
            entry["last_user_at"] = stat.st_mtime
            if entry != meta:
                state.session_meta[key] = entry
                changed = True
            continue
        refresh_process_cache = history_cache_has_process_only_preview(meta)
        cache_ok = (
            not refresh_process_cache
            and float(meta.get("cache_mtime") or 0) == float(stat.st_mtime)
            and int(meta.get("cache_size") or -1) == int(stat.st_size)
            and "preview" in meta
            and "rounds" in meta
            and "last_user_at" in meta
            and "ui_preview_messages" in meta
        )
        if cache_ok:
            rows.append((
                path,
                float(meta.get("last_user_at") or stat.st_mtime),
                str(meta.get("preview") or ""),
                int(meta.get("rounds") or 0),
                compact_description(str(meta.get("description") or "")),
            ))
            continue
        try:
            with open(path, encoding="utf-8", errors="replace") as fh:
                content = fh.read()
        except OSError:
            continue
        pairs = _pairs(content)
        if not pairs:
            continue
        preview = session_preview_from_pairs(pairs) or _preview_text(pairs)
        rounds = len(pairs)
        last_user_at = session_last_user_time_from_content(content, stat.st_mtime)
        desc = "" if refresh_process_cache else compact_description(str(meta.get("description") or ""))
        if not desc:
            desc = session_description_from_pairs(pairs, preview)
        preview_messages, preview_loaded, preview_total, preview_message_count = compact_ui_preview_messages_from_pairs(pairs)
        entry = dict(meta)
        entry.update({
            "cache_mtime": stat.st_mtime,
            "cache_size": stat.st_size,
            "preview": preview,
            "rounds": rounds,
            "last_user_at": last_user_at,
            "ui_preview_messages": preview_messages,
            "ui_preview_loaded_rounds": preview_loaded,
            "ui_preview_total_rounds": preview_total,
            "ui_preview_message_count": preview_message_count,
        })
        if desc:
            entry["description"] = desc
        if entry != meta:
            state.session_meta[key] = entry
            changed = True
        rows.append((path, last_user_at, preview, rounds, desc))
    missing_rows, missing_changed = missing_source_session_rows(state, existing_keys)
    if missing_changed:
        changed = True
    rows.extend(missing_rows)
    rows.sort(key=lambda item: item[1], reverse=True)
    return rows, changed


def l4_archive_zip_paths() -> list[str]:
    return sorted(glob.glob(os.path.join(L4_RAW_SESSIONS_DIR, "*.zip")))


def l4_member_time_hint(zip_path: str, member_name: str) -> float:
    match = re.match(r"^(\d{2})(\d{2})_(\d{2})(\d{2})-", os.path.basename(member_name or ""))
    zip_year = re.match(r"^(\d{4})-", os.path.basename(zip_path or ""))
    if not match or not zip_year:
        return 0.0
    try:
        return time.mktime(time.strptime(
            f"{zip_year.group(1)}-{match.group(1)}-{match.group(2)} {match.group(3)}:{match.group(4)}:00",
            "%Y-%m-%d %H:%M:%S",
        ))
    except Exception:
        return 0.0


def l4_recovery_needles(meta: dict[str, Any]) -> list[tuple[str, int]]:
    needles: list[tuple[str, int]] = []
    raw_preview_messages = meta.get("ui_preview_messages")
    if isinstance(raw_preview_messages, list):
        for item in raw_preview_messages:
            if not isinstance(item, dict):
                continue
            role = str(item.get("role") or "")
            content = clean_text(str(item.get("content") or ""))
            content = re.sub(r"^（预览）", "", content).strip()
            if len(content) >= 10:
                needles.append((content, 20 if role == "user" else 8))
    for field_name, weight in (("preview", 3), ("description", 2)):
        content = compact_description(str(meta.get(field_name) or ""), 180)
        if len(content) >= 12:
            needles.append((content, weight))
    unique: list[tuple[str, int]] = []
    seen: set[str] = set()
    for needle, weight in needles:
        if needle in seen:
            continue
        seen.add(needle)
        unique.append((needle, weight))
    return unique[:12]


def l4_archive_candidate_score(zip_path: str, member_name: str, content: str, meta: dict[str, Any]) -> int:
    score = 0
    for needle, weight in l4_recovery_needles(meta):
        if needle and needle in content:
            score += weight
    last_user_at = session_meta_epoch(meta.get("last_user_at"))
    member_time = l4_member_time_hint(zip_path, member_name)
    if last_user_at and member_time:
        if abs(last_user_at - member_time) <= 36 * 3600:
            score += 3
        elif time.strftime("%Y-%m", time.localtime(last_user_at)) == time.strftime("%Y-%m", time.localtime(member_time)):
            score += 1
    return score


def restore_missing_source_from_l4_archive(state: State, path: str, meta: dict[str, Any]) -> tuple[bool, str]:
    if os.path.exists(path):
        return True, "源文件已存在。"
    best: tuple[int, str, str, str] | None = None
    for zip_path in l4_archive_zip_paths():
        try:
            with zipfile.ZipFile(zip_path) as archive:
                for member_name in archive.namelist():
                    if not member_name.endswith(".txt"):
                        continue
                    try:
                        content = archive.read(member_name).decode("utf-8", errors="replace")
                    except Exception:
                        continue
                    score = l4_archive_candidate_score(zip_path, member_name, content, meta)
                    if score <= 0:
                        continue
                    if best is None or score > best[0]:
                        best = (score, zip_path, member_name, content)
        except Exception:
            continue
    if best is None or best[0] < 12:
        return False, "未找到可信的 L4 归档映射。"
    score, zip_path, member_name, content = best
    write_text_atomic(path, content)
    state.session_meta = load_session_meta_registry()
    key = session_key(path)
    entry = dict(state.session_meta.get(key, {}))
    entry.update({
        "source_restored_from": "L4_raw_sessions",
        "source_restored_archive": os.path.basename(zip_path),
        "source_restored_member": member_name,
        "source_restored_score": score,
        "source_restored_at": time.time(),
    })
    state.session_meta[key] = entry
    save_session_meta_registry(state.session_meta)
    return True, f"已从 L4 归档恢复源文件：{os.path.basename(zip_path)}::{member_name}"


def new_session_log_path() -> str:
    os.makedirs(MODEL_RESPONSES_DIR, exist_ok=True)
    while True:
        suffix = f"{time.time_ns() % 1_000_000_000_000:012d}{next(_SESSION_LOG_COUNTER) % 1000:03d}"
        path = os.path.join(MODEL_RESPONSES_DIR, f"model_responses_{suffix}.txt")
        if not os.path.exists(path):
            return path


def agent_llm_clients(agent: Any) -> list[Any]:
    if agent is None:
        return []
    seen: set[int] = set()
    clients: list[Any] = []
    for client in [getattr(agent, "llmclient", None), *(getattr(agent, "llmclients", []) or [])]:
        if client is None or id(client) in seen:
            continue
        seen.add(id(client))
        clients.append(client)
    return clients


def set_agent_log_path(agent: Any, path: str) -> None:
    if agent is None or not path:
        return
    agent.log_path = path
    for client in agent_llm_clients(agent):
        try:
            client.log_path = path
        except Exception:
            pass
        backend = getattr(client, "backend", None)
        if backend is not None and hasattr(backend, "log_path"):
            try:
                backend.log_path = path
            except Exception:
                pass


def agent_requires_transcript_bridge(agent: Any) -> bool:
    provider_id = agent_runtime_provider_id(agent)
    if provider_id == "genericagent":
        return False
    if is_ohmypi_runtime_agent(agent):
        return True
    return hasattr(agent, "put_runtime_task")


latest_user_message_text = history_store.latest_user_message_text


def append_model_response_transcript_turn(path: str, user_text: str, assistant_text: str) -> bool:
    return history_store.append_model_response_transcript_turn(
        path,
        user_text,
        assistant_text,
        normal_session_log_path=is_normal_session_log_path(path),
    )


def persist_transcript_bridge_turn(
    agent: Any,
    messages: list[Message],
    assistant_text: str,
    *,
    source: str,
    temporary_session: bool = False,
) -> bool:
    if temporary_session or not str(source or "").startswith("user"):
        return False
    if agent is None or agent_log_path_is_devnull(agent) or not agent_requires_transcript_bridge(agent):
        return False
    path = agent_log_path(agent)
    if not is_normal_session_log_path(path):
        return False
    user_text = latest_user_message_text(messages)
    if not user_text:
        return False
    return append_model_response_transcript_turn(path, user_text, assistant_text)


def reset_agent_runtime_context_no_snapshot(agent: Any, history: Optional[list[dict[str, Any]]] = None) -> None:
    if agent is None:
        return
    try:
        agent.abort()
    except Exception:
        pass
    if hasattr(agent, "history"):
        agent.history = []
    backend_history = list(history or [])
    for client in agent_llm_clients(agent):
        backend = getattr(client, "backend", None)
        if backend is not None and hasattr(backend, "history"):
            backend.history = list(backend_history)
        if hasattr(client, "last_tools"):
            client.last_tools = ""
    if hasattr(agent, "handler"):
        agent.handler = None
    if hasattr(agent, "_ga_tui_pending_key_info"):
        setattr(agent, "_ga_tui_pending_key_info", "")
    for attr in ("_ga_tui_runtime_context_full_sent", "_ga_tui_runtime_context_prompt_count"):
        if hasattr(agent, attr):
            try:
                setattr(agent, attr, 0)
            except Exception:
                pass
    reset_runtime_session = getattr(agent, "reset_runtime_session", None)
    if callable(reset_runtime_session):
        try:
            reset_runtime_session()
        except Exception:
            pass


def write_text_atomic(path: str, text: str) -> None:
    os.makedirs(os.path.dirname(path), exist_ok=True)
    tmp = path + ".tmp"
    with open(tmp, "w", encoding="utf-8") as fh:
        fh.write(text)
    os.replace(tmp, path)


def legacy_import_marker_path() -> str:
    return os.path.join(SHUHENG_HOME, ".legacy_import.json")


def legacy_genericagent_history_dir() -> str:
    return os.path.join(ROOT_DIR, "temp", "model_responses")


def legacy_genericagent_memory_dir() -> str:
    return os.path.join(ROOT_DIR, "memory")


def env_flag_enabled(name: str) -> bool:
    return str(os.environ.get(name) or "").strip().lower() in {"1", "true", "yes", "on", "y"}


def env_flag_disabled(name: str) -> bool:
    return str(os.environ.get(name) or "").strip().lower() in {"0", "false", "no", "off", "n"}


def shuheng_legacy_import_allowed() -> bool:
    if env_flag_enabled("SHUHENG_DISABLE_LEGACY_IMPORT") or env_flag_disabled("SHUHENG_IMPORT_LEGACY"):
        return False
    if env_flag_enabled("SHUHENG_IMPORT_LEGACY"):
        return True
    if os.environ.get("SHUHENG_HOME") or os.environ.get("GA_TUI_HOME"):
        return False
    return normalized_path(SHUHENG_HOME) == normalized_path("~/.shuheng")


def read_json_dict_file(path: str) -> dict[str, Any]:
    try:
        with open(path, encoding="utf-8") as fh:
            raw = json.load(fh)
    except Exception:
        return {}
    return dict(raw) if isinstance(raw, dict) else {}


def merge_json_dict_file(src_path: str, dst_path: str) -> bool:
    src = read_json_dict_file(src_path)
    if not src:
        return False
    dst = read_json_dict_file(dst_path)
    merged = dict(src)
    merged.update(dst)
    if merged == dst and os.path.exists(dst_path):
        return False
    os.makedirs(os.path.dirname(dst_path), exist_ok=True)
    tmp = f"{dst_path}.tmp"
    with open(tmp, "w", encoding="utf-8") as fh:
        json.dump(merged, fh, ensure_ascii=False, indent=2, sort_keys=True)
    os.replace(tmp, dst_path)
    return True


def copy_file_if_missing(src_path: str, dst_path: str) -> bool:
    if not os.path.isfile(src_path) or os.path.exists(dst_path):
        return False
    os.makedirs(os.path.dirname(dst_path), exist_ok=True)
    shutil.copy2(src_path, dst_path)
    return True


def copy_legacy_history_to_shuheng(src_dir: str, dst_dir: str) -> dict[str, int]:
    copied = 0
    merged = 0
    if not os.path.isdir(src_dir):
        return {"copied_files": copied, "merged_json": merged}
    os.makedirs(dst_dir, exist_ok=True)
    for src_path in glob.glob(os.path.join(src_dir, "model_responses*.txt")):
        if copy_file_if_missing(src_path, os.path.join(dst_dir, os.path.basename(src_path))):
            copied += 1
    for sidecar in ("session_meta.json", "session_names.json", "session_token_usage.json"):
        src_path = os.path.join(src_dir, sidecar)
        dst_path = os.path.join(dst_dir, sidecar)
        if not os.path.exists(dst_path):
            if copy_file_if_missing(src_path, dst_path):
                copied += 1
        elif merge_json_dict_file(src_path, dst_path):
            merged += 1
    return {"copied_files": copied, "merged_json": merged}


def copy_legacy_memory_to_shuheng(src_dir: str, dst_dir: str) -> dict[str, int]:
    copied = 0
    if not os.path.isdir(src_dir):
        return {"copied_files": copied}
    for root, dirs, files in os.walk(src_dir):
        rel_root = os.path.relpath(root, src_dir)
        if rel_root.startswith(os.path.join("agent_harness", "runtime")):
            dirs[:] = []
            continue
        dirs[:] = [d for d in dirs if d not in {"__pycache__", ".git"}]
        for name in files:
            if name.endswith((".pyc", ".tmp")):
                continue
            src_path = os.path.join(root, name)
            rel_path = name if rel_root == "." else os.path.join(rel_root, name)
            dst_path = os.path.join(dst_dir, rel_path)
            if copy_file_if_missing(src_path, dst_path):
                copied += 1
    return {"copied_files": copied}


def maybe_bootstrap_shuheng_legacy_state() -> dict[str, Any]:
    global _LEGACY_STATE_BOOTSTRAP_DONE
    if _LEGACY_STATE_BOOTSTRAP_DONE:
        return {}
    _LEGACY_STATE_BOOTSTRAP_DONE = True
    if not shuheng_legacy_import_allowed():
        return {}
    marker = legacy_import_marker_path()
    if os.path.exists(marker):
        return {}
    history_src = legacy_genericagent_history_dir()
    memory_src = legacy_genericagent_memory_dir()
    history = copy_legacy_history_to_shuheng(history_src, MODEL_RESPONSES_DIR)
    memory = copy_legacy_memory_to_shuheng(memory_src, SHUHENG_MEMORY_DIR)
    report = {
        "schema_version": "shuheng.legacy_import.v1",
        "imported_at": now_iso(),
        "source_root": ROOT_DIR,
        "target_home": SHUHENG_HOME,
        "history_source": history_src,
        "memory_source": memory_src,
        "history": history,
        "memory": memory,
        "mode": "copy_missing_only",
    }
    if os.path.isdir(history_src) or os.path.isdir(memory_src):
        write_text_atomic(marker, json.dumps(report, ensure_ascii=False, indent=2, sort_keys=True) + "\n")
    return report


def normalized_workspace_id(value: str) -> str:
    raw = (value or "").strip().lower()
    raw = raw.replace(os.sep, "-")
    if os.altsep:
        raw = raw.replace(os.altsep, "-")
    raw = re.sub(r"[^a-z0-9._-]+", "-", raw)
    raw = re.sub(r"-{2,}", "-", raw).strip("._-")
    return raw[:80]


def workspace_slug(value: str) -> str:
    ascii_text = unicodedata.normalize("NFKD", value or "").encode("ascii", "ignore").decode("ascii")
    slug = normalized_workspace_id(ascii_text)
    return slug or "workspace"


def workspace_id_for_root(root: str) -> str:
    normalized = os.path.abspath(os.path.expanduser(root or os.getcwd()))
    slug = workspace_slug(os.path.basename(normalized.rstrip(os.sep)) or "workspace")
    digest = hashlib.sha256(normalized.encode("utf-8", errors="replace")).hexdigest()[:8]
    workspace_id = f"{slug}-{digest}"
    # Existing workspace directories were named with an 8-char sha1 suffix;
    # keep them discoverable while new workspaces use sha256.
    legacy_digest = hashlib.sha1(normalized.encode("utf-8", errors="replace")).hexdigest()[:8]
    legacy_workspace_id = f"{slug}-{legacy_digest}"
    legacy_path = os.path.join(SHUHENG_WORKSPACES_DIR, legacy_workspace_id)
    current_path = os.path.join(SHUHENG_WORKSPACES_DIR, workspace_id)
    if os.path.isdir(legacy_path) and not os.path.isdir(current_path):
        return legacy_workspace_id
    return workspace_id


def workspace_dir(workspace_id: str) -> str:
    workspace_id = normalized_workspace_id(workspace_id)
    return os.path.join(SHUHENG_WORKSPACES_DIR, workspace_id)


def workspace_manifest_path(workspace_id: str) -> str:
    return os.path.join(workspace_dir(workspace_id), WORKSPACE_MANIFEST_FILENAME)


def workspace_memory_path(workspace_id: str) -> str:
    return os.path.join(workspace_dir(workspace_id), WORKSPACE_MEMORY_FILENAME)


def workspace_index_path(workspace_id: str) -> str:
    return os.path.join(workspace_dir(workspace_id), WORKSPACE_INDEX_FILENAME)


def workspace_l4_index_path(workspace_id: str) -> str:
    return os.path.join(workspace_dir(workspace_id), WORKSPACE_L4_INDEX_FILENAME)


def unique_workspace_id(name: str) -> str:
    base = workspace_slug(name)
    candidate = base
    suffix = 2
    while os.path.exists(workspace_manifest_path(candidate)):
        candidate = f"{base}-{suffix}"
        suffix += 1
    return candidate


def load_workspace_manifest(workspace_id: str) -> dict[str, Any]:
    workspace_id = normalized_workspace_id(workspace_id)
    if not workspace_id:
        return {}
    manifest = read_json_dict_file(workspace_manifest_path(workspace_id))
    if not manifest:
        return {}
    if str(manifest.get("workspace_id") or "") != workspace_id:
        manifest["workspace_id"] = workspace_id
    return manifest


def list_workspaces() -> list[dict[str, Any]]:
    if not os.path.isdir(SHUHENG_WORKSPACES_DIR):
        return []
    rows: list[dict[str, Any]] = []
    for name in sorted(os.listdir(SHUHENG_WORKSPACES_DIR)):
        workspace_id = normalized_workspace_id(name)
        if not workspace_id:
            continue
        manifest = load_workspace_manifest(workspace_id)
        if manifest:
            rows.append(manifest)
    rows.sort(key=lambda row: (str(row.get("name") or "").lower(), str(row.get("workspace_id") or "")))
    return rows


def git_workspace_root(path: str) -> str:
    start = os.path.abspath(os.path.expanduser(path or os.getcwd()))
    try:
        result = subprocess.run(
            ["git", "-C", start, "rev-parse", "--show-toplevel"],
            check=False,
            stdout=subprocess.PIPE,
            stderr=subprocess.DEVNULL,
            text=True,
            timeout=2,
        )
        root = (result.stdout or "").strip()
        if result.returncode == 0 and root:
            return os.path.abspath(root)
    except Exception:
        pass
    current = start if os.path.isdir(start) else os.path.dirname(start)
    while current:
        if os.path.exists(os.path.join(current, ".git")):
            return current
        parent = os.path.dirname(current)
        if parent == current:
            break
        current = parent
    return start


def current_workspace_root() -> str:
    return git_workspace_root(os.getcwd())


def l4_zip_member_modified_at(info: zipfile.ZipInfo) -> str:
    try:
        year, month, day, hour, minute, second = info.date_time
        return f"{year:04d}-{month:02d}-{day:02d}T{hour:02d}:{minute:02d}:{second:02d}"
    except Exception:
        return ""


def build_l4_archive_index() -> dict[str, Any]:
    archives: list[dict[str, Any]] = []
    refs: list[dict[str, Any]] = []
    for archive_path in l4_archive_zip_paths():
        archive_name = os.path.basename(archive_path)
        archive_row = {"archive": archive_path, "name": archive_name, "members": 0, "error": ""}
        try:
            with zipfile.ZipFile(archive_path) as zf:
                for info in sorted(zf.infolist(), key=lambda item: item.filename):
                    if info.is_dir():
                        continue
                    ref = f"l4://{archive_name}/{info.filename}"
                    refs.append({
                        "ref": ref,
                        "archive": archive_path,
                        "archive_name": archive_name,
                        "member": info.filename,
                        "size": int(info.file_size),
                        "modified_at": l4_zip_member_modified_at(info),
                    })
                    archive_row["members"] += 1
        except Exception as exc:
            archive_row["error"] = f"{type(exc).__name__}: {exc}"
        archives.append(archive_row)
    return {
        "schema_version": "shuheng.l4_index.v1",
        "generated_at": now_iso(),
        "source_dir": L4_RAW_SESSIONS_DIR,
        "archives": archives,
        "refs_count": len(refs),
        "refs": refs,
        "mode": "non_destructive_index_only",
    }


def refresh_workspace_l4_index(workspace_id: str) -> dict[str, Any]:
    workspace_id = normalized_workspace_id(workspace_id)
    data = build_l4_archive_index()
    data["workspace_id"] = workspace_id
    write_text_atomic(workspace_l4_index_path(workspace_id), json.dumps(data, ensure_ascii=False, indent=2, sort_keys=True) + "\n")
    return data


def create_workspace(
    name: str,
    description: str = "",
    *,
    workspace_id: str = "",
    root_aliases: Optional[list[str]] = None,
    source: str = "auto.cwd_git_root",
) -> dict[str, Any]:
    clean_name = clean_text(name).strip() or "Workspace"
    workspace_id = normalized_workspace_id(workspace_id) or unique_workspace_id(clean_name)
    directory = workspace_dir(workspace_id)
    now = now_iso()
    aliases = [os.path.abspath(os.path.expanduser(item)) for item in (root_aliases or []) if str(item or "").strip()]
    manifest = {
        "schema_version": "shuheng.workspace.v1",
        "workspace_id": workspace_id,
        "name": clean_name,
        "description": clean_text(description).strip(),
        "created_at": now,
        "updated_at": now,
        "selection_mode": "auto",
        "workspace_dir": directory,
        "memory_path": workspace_memory_path(workspace_id),
        "index_path": workspace_index_path(workspace_id),
        "l4_index_path": workspace_l4_index_path(workspace_id),
        "root_aliases": aliases,
        "source": source,
    }
    os.makedirs(directory, exist_ok=True)
    write_text_atomic(workspace_manifest_path(workspace_id), json.dumps(manifest, ensure_ascii=False, indent=2, sort_keys=True) + "\n")
    if not os.path.exists(workspace_memory_path(workspace_id)):
        write_text_atomic(
            workspace_memory_path(workspace_id),
            f"# {clean_name}\n\nThis workspace file is secondary project provenance. Primary memory lives in Shuheng L0-L4 layered memory.\n",
        )
    build_workspace_index(workspace_id)
    return manifest


def write_auto_workspace_state(manifest: dict[str, Any], root: str) -> None:
    state = {
        "schema_version": "shuheng.workspace_state.v1",
        "active_workspace_id": manifest.get("workspace_id", ""),
        "workspace_root": root,
        "detected_at": now_iso(),
        "selection_mode": "auto",
        "source": "auto.cwd_git_root",
    }
    write_text_atomic(SHUHENG_WORKSPACE_STATE_PATH, json.dumps(state, ensure_ascii=False, indent=2, sort_keys=True) + "\n")


def ensure_auto_workspace(root: str = "") -> dict[str, Any]:
    workspace_root = os.path.abspath(os.path.expanduser(root or current_workspace_root()))
    workspace_id = workspace_id_for_root(workspace_root)
    name = os.path.basename(workspace_root.rstrip(os.sep)) or "Workspace"
    manifest = load_workspace_manifest(workspace_id)
    if not manifest:
        manifest = create_workspace(
            name,
            f"Auto workspace for {workspace_root}",
            workspace_id=workspace_id,
            root_aliases=[workspace_root],
            source="auto.cwd_git_root",
        )
    else:
        aliases = list(manifest.get("root_aliases") or [])
        if workspace_root not in aliases:
            aliases.append(workspace_root)
        manifest.update({
            "name": manifest.get("name") or name,
            "updated_at": now_iso(),
            "selection_mode": "auto",
            "source": manifest.get("source") or "auto.cwd_git_root",
            "root_aliases": aliases,
            "workspace_dir": workspace_dir(workspace_id),
            "memory_path": workspace_memory_path(workspace_id),
            "index_path": workspace_index_path(workspace_id),
            "l4_index_path": workspace_l4_index_path(workspace_id),
        })
        write_text_atomic(workspace_manifest_path(workspace_id), json.dumps(manifest, ensure_ascii=False, indent=2, sort_keys=True) + "\n")
        if not os.path.exists(workspace_memory_path(workspace_id)):
            write_text_atomic(
                workspace_memory_path(workspace_id),
                f"# {manifest.get('name') or name}\n\nThis workspace file is secondary project provenance. Primary memory lives in Shuheng L0-L4 layered memory.\n",
            )
        build_workspace_index(workspace_id)
    write_auto_workspace_state(manifest, workspace_root)
    return manifest


def workspace_file_record(path: str, *, root: str) -> Optional[dict[str, Any]]:
    try:
        st = os.stat(path)
    except OSError:
        return None
    return {
        "path": path,
        "label": os.path.relpath(path, root),
        "size": int(st.st_size),
        "mtime": float(st.st_mtime),
    }


def build_workspace_index(workspace_id: str) -> dict[str, Any]:
    workspace_id = normalized_workspace_id(workspace_id)
    manifest = load_workspace_manifest(workspace_id)
    if not manifest:
        return {}
    directory = workspace_dir(workspace_id)
    memory_files: list[dict[str, Any]] = []
    memory_record = workspace_file_record(workspace_memory_path(workspace_id), root=directory)
    if memory_record:
        memory_files.append(memory_record)
    l4_index = refresh_workspace_l4_index(workspace_id)
    index = {
        "schema_version": "shuheng.workspace_index.v1",
        "generated_at": now_iso(),
        "workspace": {
            "workspace_id": workspace_id,
            "name": manifest.get("name", workspace_id),
            "selection_mode": manifest.get("selection_mode") or "auto",
            "manifest_path": workspace_manifest_path(workspace_id),
            "root_aliases": list(manifest.get("root_aliases") or []),
        },
        "memory_files": memory_files,
        "l4": {
            "index_path": workspace_l4_index_path(workspace_id),
            "source_dir": L4_RAW_SESSIONS_DIR,
            "refs_count": int(l4_index.get("refs_count") or 0),
            "sample_refs": [row.get("ref", "") for row in (l4_index.get("refs") or [])[-8:] if row.get("ref")],
            "mode": "non_destructive_index_only",
        },
        "harness_refs": {
            "tasks": AGENT_TASK_LEDGER_PATH,
            "progress": AGENT_PROGRESS_LEDGER_PATH,
            "artifacts": AGENT_ARTIFACT_INDEX_PATH,
            "memory_candidates": AGENT_MEMORY_CANDIDATES_PATH,
        },
    }
    write_text_atomic(workspace_index_path(workspace_id), json.dumps(index, ensure_ascii=False, indent=2, sort_keys=True) + "\n")
    return index


def workspace_context_payload(*, security_context: str = "standard") -> dict[str, Any]:
    if normalized_security_context(security_context) == "secret":
        return {
            "included": False,
            "reason": "Secret context does not hydrate Shuheng workspace provenance memory.",
            "workspace": None,
            "items": [],
            "refs": [],
        }
    try:
        manifest = ensure_auto_workspace()
    except Exception as exc:
        return {
            "included": False,
            "reason": f"Unable to infer Shuheng workspace: {type(exc).__name__}: {exc}",
            "workspace": None,
            "items": [],
            "refs": [],
        }
    workspace_id = str(manifest.get("workspace_id") or "")
    if not manifest:
        return {
            "included": False,
            "reason": "Unable to infer Shuheng workspace.",
            "workspace": {"workspace_id": workspace_id},
            "items": [],
            "refs": [],
        }
    index = build_workspace_index(workspace_id)
    memory_text = read_text_file(workspace_memory_path(workspace_id), "")
    memory_items = compact_nonempty_lines(memory_text, limit=8, width=220)
    l4 = index.get("l4") or {}
    refs = [workspace_manifest_path(workspace_id), workspace_memory_path(workspace_id), workspace_index_path(workspace_id), workspace_l4_index_path(workspace_id)]
    return {
        "included": True,
        "reason": "Automatic Shuheng workspace is inferred as project provenance for this context pack.",
        "workspace": {
            "workspace_id": workspace_id,
            "name": manifest.get("name", workspace_id),
            "description": manifest.get("description", ""),
            "selection_mode": "auto",
            "root_aliases": list(manifest.get("root_aliases") or []),
        },
        "items": memory_items or ["(workspace provenance is empty)"],
        "refs": refs,
        "l4": {
            "refs_count": int(l4.get("refs_count") or 0),
            "index_path": l4.get("index_path", workspace_l4_index_path(workspace_id)),
            "sample_refs": l4.get("sample_refs", []),
            "mode": l4.get("mode", "non_destructive_index_only"),
        },
    }


def read_text_file(path: str, default: str = "") -> str:
    try:
        with open(path, encoding="utf-8", errors="replace") as fh:
            return fh.read()
    except Exception:
        return default


def append_text_file(path: str, text: str) -> None:
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, "a", encoding="utf-8") as fh:
        fh.write(text)


def now_iso() -> str:
    return time.strftime("%Y-%m-%dT%H:%M:%S%z", time.localtime())

_DIAGNOSTICS_ENABLED = (os.environ.get("GA_TUI_DIAGNOSTICS", "") or "").strip().lower() not in {"", "0", "false", "no", "off"}
_DIAGNOSTIC_LOCK = threading.Lock()


def log_diagnostic(scope: str, exc: BaseException, *, detail: str = "") -> None:
    """Persist a rare exception to the Shuheng log when diagnostics are on.

    This does NOT surface the error to the user; callers that need user-visible
    feedback must still set state.last_error or return a message tuple. It is a
    forensic aid so that best-effort paths (which correctly swallow exceptions
    to keep the TUI responsive) still leave evidence when GA_TUI_DIAGNOSTICS=1.
    Disabled by default to avoid writing to disk on every run.
    """
    if not _DIAGNOSTICS_ENABLED:
        return
    try:
        line = f"{now_iso()} [{scope}] {type(exc).__name__}: {exc}"
        if detail:
            line += f" | {detail}"
        with _DIAGNOSTIC_LOCK:
            os.makedirs(os.path.dirname(SHUHENG_LOG_PATH) or ".", exist_ok=True)
            with open(SHUHENG_LOG_PATH, "a", encoding="utf-8") as fh:
                fh.write(line + "\n")
    except OSError:
        # Logging must never raise; if the log is unwritable, give up silently.
        pass


def shuheng_memory_file_path(filename: str) -> str:
    return os.path.join(SHUHENG_MEMORY_DIR, filename)


def shared_user_profile_path() -> str:
    return shuheng_memory_file_path(SHUHENG_USER_PROFILE_FILENAME)


def shared_user_profile_state_path() -> str:
    return shuheng_memory_file_path(SHUHENG_USER_PROFILE_STATE_FILENAME)


def shared_user_profile_default_description() -> str:
    return (
        "The user operates Shuheng as a governed multi-agent workbench and expects "
        "main and persistent agents to share one current understanding of the user's "
        "working state, active projects, and interaction preferences."
    )


def shared_user_profile_empty_state() -> dict[str, Any]:
    now = now_iso()
    return {
        "schema_version": "shuheng.shared_user_profile.v1",
        "created_at": now,
        "updated_at": now,
        "first_interaction_at": "",
        "last_interaction_at": "",
        "last_interaction_ts": 0.0,
        "interaction_count": 0,
        "estimated_work_seconds": 0,
        "profile_description": shared_user_profile_default_description(),
        "focus_counts": {},
        "project_counts": {},
        "recent_intents": [],
        "source_counts": {},
    }


def shared_profile_sanitized_text(text: str, *, limit: int = 240) -> str:
    cleaned = strip_tui_controls(strip_subagent_memory_controls(clean_text(text or "")))
    cleaned = redact_memory_text(cleaned)
    cleaned = re.sub(r"\s+", " ", cleaned).strip()
    return truncate_cells(cleaned, limit)


def shared_profile_top_items(raw: Any, *, limit: int = 8) -> list[tuple[str, int]]:
    if not isinstance(raw, dict):
        return []
    items: list[tuple[str, int]] = []
    for key, value in raw.items():
        label = shared_profile_sanitized_text(str(key or ""), limit=80)
        if not label:
            continue
        try:
            count = max(0, int(value or 0))
        except (TypeError, ValueError):
            count = 0
        if count:
            items.append((label, count))
    items.sort(key=lambda item: (-item[1], item[0].lower()))
    return items[:limit]


def read_shared_user_profile_state() -> dict[str, Any]:
    raw = read_json_dict_file(shared_user_profile_state_path())
    state = shared_user_profile_empty_state()
    if isinstance(raw, dict):
        for key, value in raw.items():
            if key in {"focus_counts", "project_counts", "source_counts"} and not isinstance(value, dict):
                continue
            if key == "recent_intents" and not isinstance(value, list):
                continue
            state[key] = value
    state["schema_version"] = "shuheng.shared_user_profile.v1"
    if not str(state.get("profile_description") or "").strip():
        state["profile_description"] = shared_user_profile_default_description()
    focus_counts = {}
    for label, count in (state.get("focus_counts") or {}).items():
        text = str(label or "").strip()
        if re.fullmatch(r"[\u4e00-\u9fff]+", text) and text not in SHARED_USER_PROFILE_CHINESE_FOCUS_KEYWORDS:
            continue
        focus_counts[text] = count
    state["focus_counts"] = focus_counts
    return state


def shared_user_profile_focus_terms(text: str) -> list[str]:
    sanitized = shared_profile_sanitized_text(text, limit=1200)
    stopwords = {
        "the", "and", "for", "with", "this", "that", "from", "into", "about", "what",
        "怎么", "这个", "那个", "一下", "看看", "现在", "还是", "就是", "里面", "然后", "所有",
        "agent", "代理",
    }
    terms: list[str] = []
    for keyword in SHARED_USER_PROFILE_CHINESE_FOCUS_KEYWORDS:
        if keyword in sanitized:
            terms.append(keyword)
    for match in re.finditer(r"[A-Za-z][A-Za-z0-9_-]{2,}", sanitized):
        term = match.group(0).strip()
        key = term.lower()
        if key in stopwords or term in stopwords:
            continue
        if len(term) > 32:
            term = truncate_cells(term, 32)
        terms.append(term)
    return list(dict.fromkeys(terms))[:16]


def shared_user_profile_project_hints(text: str) -> list[str]:
    sanitized = shared_profile_sanitized_text(text, limit=1200)
    hints: list[str] = []
    if re.search(r"Shuheng|枢衡|agent|代理|OMP|Oh My Pi", sanitized, re.IGNORECASE):
        hints.append("Shuheng multi-agent harness")
    for match in re.finditer(r"(?:~|/home/[A-Za-z0-9._-]+|/Users/[A-Za-z0-9._-]+|\.{1,2})/[^\s，。；,;:：]+", sanitized):
        path = match.group(0).strip()
        if path:
            hints.append(truncate_cells(path, 120))
    try:
        manifest = ensure_auto_workspace()
        name = str(manifest.get("name") or manifest.get("workspace_id") or "").strip()
        if name:
            hints.append(name)
    except Exception:
        pass
    return list(dict.fromkeys(hints))[:8]


def render_shared_user_profile_markdown(profile_state: dict[str, Any]) -> str:
    focus = shared_profile_top_items(profile_state.get("focus_counts"), limit=10)
    projects = shared_profile_top_items(profile_state.get("project_counts"), limit=8)
    sources = shared_profile_top_items(profile_state.get("source_counts"), limit=6)
    recent = profile_state.get("recent_intents") if isinstance(profile_state.get("recent_intents"), list) else []
    work_seconds = int(profile_state.get("estimated_work_seconds") or 0)
    work_hours = work_seconds / 3600.0
    lines = [
        "# Shared User Profile",
        "",
        "This Shuheng-owned operational profile is shared by the main Orchestrator and persistent subagents.",
        "It is a dynamic interaction-state summary, not an approved L2 fact store. Do not store secrets here.",
        "",
        "## Profile Description",
        "",
        str(profile_state.get("profile_description") or shared_user_profile_default_description()).strip(),
        "",
        "## Current Interaction State",
        "",
        f"- interactions: {int(profile_state.get('interaction_count') or 0)}",
        f"- estimated_work_time_hours: {work_hours:.2f}",
        f"- first_interaction_at: {profile_state.get('first_interaction_at') or '-'}",
        f"- last_interaction_at: {profile_state.get('last_interaction_at') or '-'}",
        f"- updated_at: {profile_state.get('updated_at') or '-'}",
        "",
        "## Current Focus",
        "",
    ]
    lines.extend([f"- {label} ({count})" for label, count in focus] or ["- (not enough interaction evidence yet)"])
    lines.extend(["", "## Active Projects / Directions", ""])
    lines.extend([f"- {label} ({count})" for label, count in projects] or ["- (not enough interaction evidence yet)"])
    lines.extend(["", "## Recent User Intents", ""])
    for item in recent[-8:]:
        if isinstance(item, dict):
            lines.append(f"- {item.get('at', '-')} · {item.get('source', '-')} · {item.get('summary', '')}")
    if not recent:
        lines.append("- (none yet)")
    lines.extend(["", "## Interaction Sources", ""])
    lines.extend([f"- {label}: {count}" for label, count in sources] or ["- (none yet)"])
    lines.extend([
        "",
        "## Agent Usage Rule",
        "",
        "- All agents should use this profile as shared user-state context.",
        "- If this profile conflicts with the user's current explicit instruction, obey the current instruction and treat this file as stale evidence.",
        "- Durable long-term facts and preferences still require Shuheng memory-candidate governance unless the user explicitly asks this profile state to be updated.",
        "",
    ])
    return "\n".join(lines)


def write_shared_user_profile_state(profile_state: dict[str, Any]) -> None:
    os.makedirs(SHUHENG_MEMORY_DIR, exist_ok=True)
    write_text_atomic(
        shared_user_profile_state_path(),
        json.dumps(profile_state, ensure_ascii=False, indent=2, sort_keys=True) + "\n",
    )
    write_text_atomic(shared_user_profile_path(), render_shared_user_profile_markdown(profile_state))


def ensure_shared_user_profile_files() -> dict[str, Any]:
    profile_state = read_shared_user_profile_state()
    if not os.path.exists(shared_user_profile_path()) or not os.path.exists(shared_user_profile_state_path()):
        write_shared_user_profile_state(profile_state)
    return profile_state


def shared_user_profile_payload(*, max_chars: int = 2600) -> dict[str, Any]:
    profile_state = ensure_shared_user_profile_files()
    text = redact_memory_text(read_text_file(shared_user_profile_path(), "")).strip()
    if len(text) > max_chars:
        text = text[:max_chars].rstrip() + "\n...[truncated]"
    return {
        "schema_version": "shuheng.shared_user_profile.v1",
        "included": True,
        "reason": "Shared operational user profile and current work-state context for all Shuheng agents.",
        "path": shared_user_profile_path(),
        "state_path": shared_user_profile_state_path(),
        "profile_description": str(profile_state.get("profile_description") or ""),
        "interaction_count": int(profile_state.get("interaction_count") or 0),
        "estimated_work_seconds": int(profile_state.get("estimated_work_seconds") or 0),
        "last_interaction_at": str(profile_state.get("last_interaction_at") or ""),
        "focus": [label for label, _count in shared_profile_top_items(profile_state.get("focus_counts"), limit=8)],
        "projects": [label for label, _count in shared_profile_top_items(profile_state.get("project_counts"), limit=6)],
        "recent_intents": list(profile_state.get("recent_intents") or [])[-6:],
        "text": text or "(empty shared user profile)",
        "refs": [shared_user_profile_path(), shared_user_profile_state_path()],
    }


def record_shared_user_profile_interaction(
    text: str,
    *,
    source: str,
    state: Optional[State] = None,
) -> dict[str, Any]:
    if state is not None and (state.temporary_session or state.secret_vault.unlocked):
        return read_shared_user_profile_state()
    source = str(source or "user").strip() or "user"
    if not (source.startswith("user") or source in {"subagent_chat", "agent_home_input", "main_home_input", "web_console"}):
        return read_shared_user_profile_state()
    summary = shared_profile_sanitized_text(text, limit=180)
    if not summary:
        return read_shared_user_profile_state()
    profile_state = read_shared_user_profile_state()
    now_ts = time.time()
    now = now_iso()
    last_ts = 0.0
    try:
        last_ts = float(profile_state.get("last_interaction_ts") or 0.0)
    except (TypeError, ValueError):
        last_ts = 0.0
    if not profile_state.get("first_interaction_at"):
        profile_state["first_interaction_at"] = now
    if last_ts > 0:
        delta = max(0.0, now_ts - last_ts)
        if 30 <= delta <= 6 * 3600:
            profile_state["estimated_work_seconds"] = int(profile_state.get("estimated_work_seconds") or 0) + int(min(delta, 2 * 3600))
    profile_state["last_interaction_at"] = now
    profile_state["last_interaction_ts"] = now_ts
    profile_state["updated_at"] = now
    profile_state["interaction_count"] = int(profile_state.get("interaction_count") or 0) + 1

    focus_counts = dict(profile_state.get("focus_counts") or {})
    for term in shared_user_profile_focus_terms(summary):
        focus_counts[term] = int(focus_counts.get(term) or 0) + 1
    profile_state["focus_counts"] = dict(shared_profile_top_items(focus_counts, limit=40))

    project_counts = dict(profile_state.get("project_counts") or {})
    for project in shared_user_profile_project_hints(summary):
        project_counts[project] = int(project_counts.get(project) or 0) + 1
    profile_state["project_counts"] = dict(shared_profile_top_items(project_counts, limit=24))

    source_counts = dict(profile_state.get("source_counts") or {})
    source_counts[source] = int(source_counts.get(source) or 0) + 1
    profile_state["source_counts"] = dict(shared_profile_top_items(source_counts, limit=16))

    recent = [item for item in (profile_state.get("recent_intents") or []) if isinstance(item, dict)]
    recent.append({"at": now, "source": source, "summary": summary})
    profile_state["recent_intents"] = recent[-12:]
    write_shared_user_profile_state(profile_state)
    try:
        write_ohmypi_memory_prompt(root_dir=SHUHENG_HOME, harness_dir=AGENT_HARNESS_DIR)
    except Exception:
        pass
    return profile_state


def shuheng_l4_index_path() -> str:
    return os.path.join(L4_RAW_SESSIONS_DIR, SHUHENG_L4_INDEX_FILENAME)


def genericagent_asset_path(filename: str) -> str:
    return os.path.join(ROOT_DIR, "assets", filename)


def default_shuheng_l1_text() -> str:
    template = read_text_file(genericagent_asset_path("global_mem_insight_template.txt"))
    if template.strip():
        return template
    return (
        "# [Global Memory Insight]\n"
        "Read L2 or list L3 when needed.\n"
        "L0(META-SOP): memory_management_sop\n"
        "L2: global_mem.txt\n"
        "L3: memory/*.md or *.py\n"
        "L4: L4_raw_sessions/ historical sessions\n"
    )


def default_shuheng_l0_text() -> str:
    source = read_text_file(os.path.join(ROOT_DIR, "memory", SHUHENG_L0_FILENAME))
    if source.strip():
        return source
    return (
        "# Memory Management SOP\n\n"
        "## Core Axioms\n\n"
        "1. No Execution, No Memory. Only action-verified facts may become long-term memory.\n"
        "2. Existing verified memory must not be overwritten or deleted casually.\n"
        "3. Do not store volatile state, secrets, or unverified assumptions.\n"
        "4. Keep upper layers as short pointers to lower layers.\n\n"
        "## Layers\n\n"
        "- L1: global_mem_insight.txt, short routing/index prompt.\n"
        "- L2: global_mem.txt, approved global facts.\n"
        "- L3: memory/*.md or *.py, reusable SOPs/tools.\n"
        "- L4: L4_raw_sessions/, historical raw sessions by reference only.\n"
    )


def refresh_shuheng_l4_index() -> dict[str, Any]:
    data = build_l4_archive_index()
    data["index_path"] = shuheng_l4_index_path()
    write_text_atomic(shuheng_l4_index_path(), json.dumps(data, ensure_ascii=False, indent=2, sort_keys=True) + "\n")
    return data


def ensure_shuheng_layered_memory_files() -> dict[str, str]:
    maybe_bootstrap_shuheng_legacy_state()
    os.makedirs(SHUHENG_MEMORY_DIR, exist_ok=True)
    os.makedirs(L4_RAW_SESSIONS_DIR, exist_ok=True)
    paths = {
        "memory_dir": SHUHENG_MEMORY_DIR,
        "l0": shuheng_memory_file_path(SHUHENG_L0_FILENAME),
        "l1": shuheng_memory_file_path(SHUHENG_L1_FILENAME),
        "l2": shuheng_memory_file_path(SHUHENG_L2_FILENAME),
        "l3_dir": SHUHENG_MEMORY_DIR,
        "l4_dir": L4_RAW_SESSIONS_DIR,
        "l4_index": shuheng_l4_index_path(),
        "user_profile": shared_user_profile_path(),
        "user_profile_state": shared_user_profile_state_path(),
    }
    if not os.path.exists(paths["l2"]):
        write_text_atomic(paths["l2"], "# [Global Memory - L2]\n")
    if not os.path.exists(paths["l1"]):
        write_text_atomic(paths["l1"], default_shuheng_l1_text())
    if not os.path.exists(paths["l0"]):
        write_text_atomic(paths["l0"], default_shuheng_l0_text())
    ensure_shared_user_profile_files()
    refresh_shuheng_l4_index()
    return paths


def shuheng_memory_structure_text() -> str:
    paths = ensure_shuheng_layered_memory_files()
    return (
        f"Facts(L2): {paths['l2']} | "
        f"Shuheng CodeRoot: {APP_ROOT_DIR} | "
        f"SOPs(L3): {paths['memory_dir']}/*.md or *.py | "
        f"META-SOP(L0): {paths['l0']}\n"
        f"L4: {paths['l4_dir']} historical sessions; index: {paths['l4_index']}\n"
        "L1 Insight is the short routing index. Read L0 before proposing any long-term memory update. "
        "Long-term writes are candidate-only through Shuheng governance."
    )


def shuheng_layered_memory_prompt(*, max_l1_chars: int = 3500) -> str:
    paths = ensure_shuheng_layered_memory_files()
    insight_raw = read_text_file(paths["l1"], "")[:max_l1_chars]
    insight = redact_memory_text(insight_raw).strip() or "(empty L1 index)"
    shared_profile = shared_user_profile_payload(max_chars=2200)
    return "\n".join([
        f"cwd = {os.path.join(AGENT_HARNESS_DIR, 'runtime')} (./)",
        "",
        f"[Memory] ({paths['memory_dir']})",
        shuheng_memory_structure_text(),
        "",
        f"[Shared User Profile] ({shared_profile.get('path', '')})",
        str(shared_profile.get("text") or "(empty shared user profile)"),
        "",
        f"{paths['l1']}:",
        insight,
    ])


def shuheng_layered_memory_payload() -> dict[str, Any]:
    paths = ensure_shuheng_layered_memory_files()
    l4_index = read_json_dict_file(paths["l4_index"])
    shared_profile = shared_user_profile_payload()
    l1_items = compact_nonempty_lines(read_text_file(paths["l1"], ""), limit=6, width=220)
    items = [
        f"Shared user profile: {paths['user_profile']}",
        f"L0 META-SOP: {paths['l0']}",
        f"L1 index: {paths['l1']}",
        f"L2 facts: {paths['l2']}",
        f"L3 SOP/tools root: {paths['l3_dir']}",
        f"L4 raw sessions: {paths['l4_dir']} refs={int(l4_index.get('refs_count') or 0)}",
    ]
    if l1_items:
        items.append("L1 preview: " + " | ".join(l1_items[:3]))
    if shared_profile.get("focus"):
        items.append("User focus: " + ", ".join(str(item) for item in (shared_profile.get("focus") or [])[:4]))
    return {
        "schema_version": "shuheng.layered_memory.v1",
        "included": True,
        "mode": "genericagent_l0_l4",
        "reason": "GenericAgent-style Shuheng layered memory is the primary runtime memory context.",
        "items": items,
        "refs": [paths["user_profile"], paths["user_profile_state"], paths["l0"], paths["l1"], paths["l2"], paths["l3_dir"], paths["l4_dir"], paths["l4_index"]],
        "paths": paths,
        "shared_user_profile": shared_profile,
        "prompt": shuheng_layered_memory_prompt(),
        "l4": {
            "refs_count": int(l4_index.get("refs_count") or 0),
            "index_path": paths["l4_index"],
            "mode": l4_index.get("mode", "non_destructive_index_only"),
            "sample_refs": [row.get("ref", "") for row in (l4_index.get("refs") or [])[-8:] if row.get("ref")],
        },
    }


def short_uid(prefix: str) -> str:
    return f"{prefix}_{time.time_ns():x}_{os.getpid():x}"


def append_jsonl(path: str, payload: dict[str, Any]) -> None:
    ledger_store.append_jsonl(path, payload)


def write_bytes_atomic(path: str, data: bytes) -> None:
    os.makedirs(os.path.dirname(path), exist_ok=True)
    tmp = path + ".tmp"
    with open(tmp, "wb") as fh:
        fh.write(data)
    os.replace(tmp, path)


