def artifact_path_from_uri(uri: str) -> str:
    uri = (uri or "").strip()
    if uri.startswith("artifact://"):
        rel = uri[len("artifact://"):].replace("/", os.sep)
        return os.path.normpath(os.path.join(AGENT_HARNESS_DIR, rel))
    return uri if os.path.isabs(uri) else ""


