def context_layers_for_task(
    state: State,
    sub: SubAgentRuntime,
    objective: str,
    task_id: str,
    *,
    profile: str,
    memory: str,
    recent_mail: list[dict[str, Any]],
    task_contract: dict[str, Any],
    memory_pack: dict[str, Any],
    layered_memory: Optional[dict[str, Any]] = None,
    workspace_context: Optional[dict[str, Any]] = None,
    role: str = "",
) -> dict[str, Any]:
    role = normalized_role(role) if role else normalized_subagent_role(sub.role)
    layered_memory = layered_memory or shuheng_layered_memory_payload()
    shared_profile = shared_user_profile_payload()
    workspace_context = workspace_context or {}
    if sub.security_context == "secret":
        recent_tasks: list[dict[str, Any]] = []
        recent_progress: list[dict[str, Any]] = []
        recent_traces: list[dict[str, Any]] = []
        recent_artifacts: list[dict[str, Any]] = []
    else:
        recent_tasks = read_jsonl(AGENT_TASK_LEDGER_PATH, limit=8)
        recent_progress = recent_progress_records(limit=8)
        recent_traces = read_jsonl(AGENT_TRACES_PATH, limit=8)
        recent_artifacts = list(artifact_index_latest().values())[-8:]
    return context_pack_store.context_layers_for_task(
        role=role,
        security_context=sub.security_context,
        objective=objective,
        profile=profile,
        memory=memory,
        task_contract=task_contract,
        memory_pack=memory_pack,
        source_policy=source_policy_for_role(role, security_context=sub.security_context),
        shared_profile=shared_profile,
        layered_memory=layered_memory,
        workspace_context=workspace_context,
        recent_tasks=recent_tasks,
        recent_progress=recent_progress,
        recent_traces=recent_traces,
        recent_artifacts=recent_artifacts,
        active_session=state.current_title,
        subagent_status=sub.status,
    )


def build_context_pack(
    state: State,
    sub: SubAgentRuntime,
    objective: str,
    task_id: str,
    parent_task_id: str = "",
    *,
    permission_profile: str = PERMISSION_PROFILE_STANDARD,
    role_override: str = "",
) -> tuple[dict[str, Any], str]:
    role = normalized_role(role_override) if role_override else normalized_subagent_role(sub.role)
    template = role_template(role)
    profile = subagent_profile_text(sub).strip()
    memory = subagent_memory_text(sub).strip() if sub.persistent else ""
    recent_mail = [] if sub.security_context == "secret" else read_jsonl(AGENT_MAIL_PATH, limit=8)
    task_contract = task_contract_for_role(role, objective)
    context_policy = context_policy_for_task(objective, security_context=sub.security_context)
    permissions = permissions_for_role(role, security_context=sub.security_context, permission_profile=permission_profile)
    layered_memory = shuheng_layered_memory_payload()
    shared_profile = shared_user_profile_payload()
    workspace_context = workspace_context_payload(security_context=sub.security_context)
    skill_refs = normalize_subagent_skill_refs(sub.skill_refs)
    skill_pack = subagent_skill_pack_for_refs(skill_refs)
    memory_pack = memory_hydration_pack(
        task_id=task_id,
        sub=sub,
        profile=profile,
        memory=memory,
        recent_mail=recent_mail,
        layered_memory=layered_memory,
        workspace_context=workspace_context,
    )
    layers = context_layers_for_task(
        state,
        sub,
        objective,
        task_id,
        profile=profile,
        memory=memory,
        recent_mail=recent_mail,
        task_contract=task_contract,
        memory_pack=memory_pack,
        layered_memory=layered_memory,
        workspace_context=workspace_context,
        role=role,
    )
    pack = {
        "schema_version": "contextpack.v1",
        "context_pack_id": short_uid("ctx"),
        "task_id": task_id,
        "parent_task_id": parent_task_id,
        "created_at": now_iso(),
        "for_agent": {
            "id": sub.agent_id,
            "name": sub.name,
            "role": role,
            "home": sub.home,
            "security_context": sub.security_context,
        },
        "objective": objective,
        "role_template": template,
        "budget": default_task_budget(role),
        "permission_profile": permissions.get("permission_profile", PERMISSION_PROFILE_STANDARD),
        "permissions": permissions,
        "skill_refs": skill_refs,
        "skill_pack": skill_pack,
        "context_policy": context_policy,
        "task": task_contract,
        "task_brief": {
            "objective": objective,
            "non_goals": task_contract.get("non_goals", []),
            "success_criteria": task_contract.get("success_criteria", []),
            "boundaries": task_contract.get("boundaries", []),
            "stop_condition": task_contract.get("stop_condition", ""),
            "output_contract": task_contract.get("output_contract", {}),
            "source_policy": source_policy_for_role(role, security_context=sub.security_context),
        },
        "source_policy": source_policy_for_role(role, security_context=sub.security_context),
        "layered_memory": layered_memory,
        "shared_user_profile": shared_profile,
        "memory_pack": memory_pack,
        "workspace_context": workspace_context,
        "layers": layers,
        "risks": risks_for_action("read_only", role, objective),
        "approval": approval_metadata(),
        "output_contract": role_output_contract(role),
        "profile_excerpt": profile[:4000],
        "memory_excerpt": memory[:4000],
        "recent_agent_mail_refs": [
            {
                "message_id": row.get("message_id", ""),
                "intent": row.get("intent", ""),
                "status": row.get("status", ""),
                "task_id": row.get("task_id", ""),
                "artifact_refs": row.get("artifact_refs", []),
            }
            for row in recent_mail
        ],
        "state": {
            "active_session": state.current_title,
            "main_status": state.status,
            "subagent_status": sub.status,
        },
    }
    if sub.security_context == "secret":
        ok, ref = secret_write_subagent_json(state, "subagent-context-packs", task_id, pack)
        return pack, ref if ok else "secret://subagents/context-pack-unavailable"
    directory = os.path.join(AGENT_CONTEXT_PACKS_DIR, sub.agent_id)
    os.makedirs(directory, exist_ok=True)
    path = os.path.join(directory, f"{task_id}.json")
    write_text_atomic(path, json.dumps(pack, ensure_ascii=False, indent=2, sort_keys=True) + "\n")
    append_artifact_index(
        path,
        artifact_type="context_pack",
        source_task_id=task_id,
        provenance={"generated_by": "orchestrator.main", "for_agent": sub.agent_id, "role": role},
        content_type="application/json",
    )
    return pack, harness_artifact_uri(path)


def build_main_runtime_context_pack(
    state: State,
    objective: str,
    task_id: str,
    parent_task_id: str = "",
) -> tuple[dict[str, Any], str]:
    permission_profile = default_omp_permission_profile()
    main_worker = SubAgentRuntime(
        agent_id="orchestrator.main",
        name="Shuheng Main Orchestrator",
        home=AGENT_HARNESS_DIR,
        role="main_orchestrator",
        security_context="secret" if state.secret_vault.unlocked else "standard",
        owner_session=active_ui_session_key(state),
        persistent=False,
        agent=state.agent,
        status=state.status,
        profile_text=(
            "Primary Shuheng Orchestrator. It owns planning, routing, policy gates, "
            "task ledgers, artifact refs, trace, and memory-candidate governance around OMP."
        ),
    )
    return build_context_pack(
        state,
        main_worker,
        objective,
        task_id,
        parent_task_id=parent_task_id,
        permission_profile=permission_profile,
        role_override="main_orchestrator",
    )


