def ohmypi_tui_readonly_host_tool_definitions() -> list[RpcHostToolDefinition]:
    return [
        RpcHostToolDefinition(
            name=OHMYPI_TUI_QUERY_TOOL_NAME,
            label="Shuheng Query",
            description=(
                "Read-only Shuheng governance query. Use it to inspect runtime providers, "
                "capabilities, agents, tasks, approval metadata, and artifact refs. It never approves, "
                "writes memory, edits artifacts, mutates ledgers, or sends messages to agents. "
                "A spawned/copied persona is not a persistent Shuheng agent reply."
            ),
            parameters={
                "type": "object",
                "additionalProperties": False,
                "properties": {
                    "endpoint": {
                        "type": "string",
                        "enum": list(OHMYPI_TUI_QUERY_ENDPOINTS),
                        "description": "Read-only governance endpoint to query.",
                    },
                    "args": {
                        "type": "object",
                        "description": "Endpoint-specific filters such as target, task_id, status, include_completed, or limit.",
                        "additionalProperties": True,
                    },
                },
                "required": ["endpoint"],
            },
        )
    ]


def ohmypi_typed_readonly_host_tool_definitions() -> list[RpcHostToolDefinition]:
    common_params = {
        "type": "object",
        "additionalProperties": True,
        "properties": {
            "target": {"type": "string", "description": "Agent id or unique agent name when the tool needs a target."},
            "task_id": {"type": "string", "description": "Task id when the tool needs a task."},
            "objective": {"type": "string", "description": "Objective for matching agents or generating memory context."},
            "limit": {"type": "integer", "description": "Maximum number of records to return."},
            "status": {"type": "string", "description": "Optional status filter."},
        },
    }
    descriptions = {
        "agent_list": "Read bounded Shuheng worker records; does not send messages or load/chat with agents.",
        "agent_get": "Read one Shuheng worker record by id or unique name, including identity/interaction rules; does not chat.",
        "agent_match": "Find suitable Shuheng workers for an objective; reuse means target that agent_id, not clone its persona.",
        "task_list": "Read task ledger rows.",
        "task_get": "Read one task plus related approvals, artifacts, and traces.",
        "approval_list": "Read approval metadata without granting approval.",
        "artifact_list": "Read artifact references and metadata.",
        "capability_list": "Read roles, tools, runtime providers, and gateway capabilities.",
        "schedule_list": "Read scheduled task registry and run audit metadata.",
        "memory_context_get": "Generate and return a Shuheng memory/context pack artifact reference for OMP execution.",
    }
    return [
        RpcHostToolDefinition(
            name=name,
            label=name.replace("_", "."),
            description=descriptions[name],
            parameters=common_params,
        )
        for name in OHMYPI_TYPED_READONLY_TOOL_NAMES
    ]


