def ohmypi_runtime_registry_snapshot() -> dict[str, Any]:
    data = agent_runtime_registry(write_memory_prompt_file=False).to_record()
    data["updated_at"] = now_iso()
    data["registry_path"] = AGENT_RUNTIME_REGISTRY_PATH
    return data


def ohmypi_tui_memory_context_get(state: Optional[State], args: dict[str, Any]) -> dict[str, Any]:
    if state is None:
        return tui_query_error("TUI state is not bound; memory_context_get requires an active TUI state.")
    target = str(args.get("target") or args.get("agent_id") or "").strip()
    objective = clean_text(str(args.get("objective") or args.get("prompt") or "OMP runtime context request")).strip()
    task_id = str(args.get("task_id") or "").strip() or short_uid("ctx-task")
    if target:
        sub = resolve_subagent(state, target)
        if sub is None:
            return tui_query_error("Target subagent was not found or was ambiguous.", target=target)
        pack, context_ref = build_context_pack(state, sub, objective, task_id, parent_task_id=str(args.get("parent_task_id") or ""))
    else:
        pack, context_ref = build_main_runtime_context_pack(state, objective, task_id, parent_task_id=str(args.get("parent_task_id") or ""))
    return tui_query_ok(
        "memory.context",
        context_pack_ref=context_ref,
        context_pack=tui_query_json_safe(pack),
    )


def ohmypi_proposal_error(message: str, **extra: Any) -> dict[str, Any]:
    return {
        "schema_version": "ga-tui.proposal.v1",
        "status": "error",
        "error": message,
        **extra,
    }


def ohmypi_proposal_ok(kind: str, **payload: Any) -> dict[str, Any]:
    return {
        "schema_version": "ga-tui.proposal.v1",
        "kind": kind,
        "status": "ok",
        "generated_at": now_iso(),
        **payload,
    }


def ohmypi_tui_propose_memory_candidate(state: Optional[State], args: dict[str, Any]) -> dict[str, Any]:
    if state is None:
        return ohmypi_proposal_error("TUI state is not bound; memory candidates require an active TUI state.")
    target = str(args.get("target") or "").strip()
    statement = clean_text(str(args.get("statement") or "")).strip()
    if not target:
        return ohmypi_proposal_error("Missing target for memory candidate proposal.", proposal_type="memory_candidate")
    if not statement:
        return ohmypi_proposal_error("Missing statement for memory candidate proposal.", proposal_type="memory_candidate")
    target_sub = resolve_subagent(state, target)
    if target_sub is None:
        return ohmypi_proposal_error(
            "Target subagent was not found or was ambiguous.",
            proposal_type="memory_candidate",
            target=target,
        )
    task_id = str(args.get("task_id") or "").strip()
    evidence_ref = str(args.get("evidence_ref") or "").strip() or "runtime://provider/ohmypi/host_tool"
    source = str(args.get("source") or "").strip() or "agent:ohmypi_host_tool"
    candidate_start = len(read_jsonl(AGENT_MEMORY_CANDIDATES_PATH))
    approval_start = len(read_jsonl(AGENT_APPROVALS_PATH))
    result_message = queue_curated_memory_candidate(
        state,
        target_sub,
        statement,
        source=source,
        evidence_ref=evidence_ref,
        task_id=task_id,
    )
    candidate_rows = read_jsonl(AGENT_MEMORY_CANDIDATES_PATH)[candidate_start:]
    approval_rows = read_jsonl(AGENT_APPROVALS_PATH)[approval_start:]
    if any(str(row.get("status") or "") == "rejected" for row in candidate_rows) or "已拒绝" in result_message:
        result_status = "rejected"
    elif candidate_rows or approval_rows or "等待审批" in result_message:
        result_status = "queued"
    elif "已忽略" in result_message or "不写入" in result_message or "临时会话" in result_message:
        result_status = "ignored"
    else:
        result_status = "returned"
    return ohmypi_proposal_ok(
        "memory_candidate",
        proposal_type="memory_candidate",
        result_status=result_status,
        result_message=result_message,
        target_subagent=target_sub.agent_id,
        candidate_ids=[str(row.get("candidate_id") or "") for row in candidate_rows if row.get("candidate_id")],
        approval_ids=[str(row.get("approval_id") or "") for row in approval_rows if row.get("approval_id")],
        artifact_refs=[
            ref
            for row in candidate_rows
            for ref in (row.get("artifact_refs") if isinstance(row.get("artifact_refs"), list) else [])
            if ref
        ],
    )


def ohmypi_tui_propose_ga_control(state: Optional[State], args: dict[str, Any]) -> dict[str, Any]:
    if state is None:
        return ohmypi_proposal_error("TUI state is not bound; ga_control proposals require an active TUI state.")
    control = args.get("control")
    if not isinstance(control, dict):
        return ohmypi_proposal_error("Missing current-schema control object.", proposal_type="ga_control")
    schema = str(control.get("schema_version") or "").strip().lower()
    if schema not in {GA_CONTROL_SCHEMA, AGENT_TASK_SCHEMA}:
        return ohmypi_proposal_error(
            "Control proposals must use ga-control.v2 or agenttask.v2 schema_version.",
            proposal_type="ga_control",
            schema_version=schema,
        )
    controls = controls_from_json_payload(control, require_known=True)
    if not controls:
        return ohmypi_proposal_error(
            "Control proposal parsed but contained no known current-schema action.",
            proposal_type="ga_control",
        )
    text = "<ga-control>" + json.dumps(control, ensure_ascii=False, separators=(",", ":")) + "</ga-control>"
    result_lines = apply_tui_controls_from_text(
        state,
        text,
        source="agent:ohmypi_host_tool",
        default_target=str(args.get("default_target") or "current"),
    )
    return ohmypi_proposal_ok(
        "ga_control",
        proposal_type="ga_control",
        control_count=len(controls),
        result_lines=tui_query_json_safe(result_lines),
    )


def ohmypi_tui_propose_host_tool_handler(state: Optional[State], args: dict[str, Any]) -> dict[str, Any]:
    if not isinstance(args, dict):
        return ohmypi_proposal_error("Host tool arguments must be an object.")
    proposal_type = str(args.get("proposal_type") or "").strip()
    try:
        if proposal_type == "memory_candidate":
            return ohmypi_tui_propose_memory_candidate(state, args)
        if proposal_type == "ga_control":
            return ohmypi_tui_propose_ga_control(state, args)
        return ohmypi_proposal_error(
            "Unsupported proposal_type.",
            proposal_type=proposal_type,
            supported_proposal_types=list(OHMYPI_TUI_PROPOSAL_TYPES),
        )
    except Exception as exc:
        return ohmypi_proposal_error(
            f"{type(exc).__name__}: {exc}",
            proposal_type=proposal_type,
        )


def ohmypi_tui_query_endpoint(state: Optional[State], endpoint: str, endpoint_args: dict[str, Any]) -> dict[str, Any]:
    if endpoint == "runtime_registry":
        return tui_query_ok(
            "runtime.registry",
            runtime_registry=tui_query_json_safe(ohmypi_runtime_registry_snapshot()),
        )
    if endpoint == "model_orchestration":
        return tui_query_ok(
            "model.orchestration",
            model_orchestration=tui_query_json_safe(model_orchestration_registry(state)),
        )
    if endpoint == "capability_registry" or endpoint == "capability_list":
        return tui_query_ok(
            "capability.registry",
            capabilities=tui_query_json_safe(gateway_capability_registry(state, write_runtime_artifacts=False)),
        )
    if endpoint == "agent_list":
        return tui_tool_agent_list(state, endpoint_args)
    if endpoint == "agent_get":
        return tui_tool_agent_get(state, endpoint_args)
    if endpoint == "agent_match":
        return tui_tool_agent_match(state, endpoint_args)
    if endpoint == "task_list":
        return tui_tool_task_list(state, endpoint_args)
    if endpoint == "task_get":
        return tui_tool_task_get(state, endpoint_args)
    if endpoint == "approval_list":
        return tui_tool_approval_list(state, endpoint_args)
    if endpoint == "artifact_list":
        return tui_tool_artifact_list(state, endpoint_args)
    if endpoint == "schedule_list":
        return tui_tool_schedule_list(state, endpoint_args)
    if endpoint == "memory_context_get":
        return ohmypi_tui_memory_context_get(state, endpoint_args)
    return tui_query_error(
        "Unsupported endpoint.",
        endpoint=endpoint,
        supported_endpoints=list(OHMYPI_TUI_QUERY_ENDPOINTS),
    )


def ohmypi_tui_host_tool_handler(state: Optional[State] = None):
    def _handler(tool_name: str, args: dict[str, Any]) -> dict[str, Any]:
        if tool_name in OHMYPI_TYPED_READONLY_TOOL_NAMES:
            return ohmypi_tui_query_endpoint(state, tool_name, args if isinstance(args, dict) else {})
        if tool_name == "proposal_submit":
            return ohmypi_tui_propose_host_tool_handler(state, args if isinstance(args, dict) else {})
        if tool_name == "memory_candidate_submit":
            payload = dict(args) if isinstance(args, dict) else {}
            payload["proposal_type"] = "memory_candidate"
            return ohmypi_tui_propose_memory_candidate(state, payload)
        if tool_name == "schedule_create":
            return tui_tool_schedule_create(state, args if isinstance(args, dict) else {})
        if tool_name == OHMYPI_TUI_PROPOSE_TOOL_NAME:
            return ohmypi_tui_propose_host_tool_handler(state, args)
        if tool_name != OHMYPI_TUI_QUERY_TOOL_NAME:
            return tui_query_error("Unsupported host tool.", tool_name=tool_name)
        if not isinstance(args, dict):
            return tui_query_error("Host tool arguments must be an object.")
        endpoint = str(args.get("endpoint") or "").strip()
        raw_endpoint_args = args.get("args")
        if raw_endpoint_args is None:
            endpoint_args = {str(key): value for key, value in args.items() if key != "endpoint"}
        elif isinstance(raw_endpoint_args, dict):
            endpoint_args = raw_endpoint_args
        else:
            return tui_query_error("args must be an object.", endpoint=endpoint)
        return ohmypi_tui_query_endpoint(state, endpoint, endpoint_args)

    return _handler


def ohmypi_tui_query_host_tool_handler(state: Optional[State] = None):
    return ohmypi_tui_host_tool_handler(state)


def ohmypi_model_api_for_entry(entry: LLMConfigEntry) -> str:
    cfg_type = str(entry.cfg_type or "").lower()
    if model_config_uses_anthropic_messages(cfg_type, entry.cfg):
        return "anthropic-messages"
    if normalized_model_api_mode(entry.cfg.get("api_mode")) in {"responses", "response", "openai_responses"}:
        return "openai-responses"
    return "openai-completions"


def ohmypi_provider_id_for_entry(entry: LLMConfigEntry, index: int) -> str:
    seed = "\0".join([
        str(index),
        config_display_name(entry),
        str(entry.cfg.get("apibase") or ""),
        str(entry.cfg.get("model") or ""),
    ])
    digest = hashlib.sha256(seed.encode("utf-8", errors="replace")).hexdigest()[:8]
    base = compact_identifier(config_display_name(entry) or str(entry.cfg.get("apibase") or ""), 28)
    return f"ga-tui-{base}-{digest}"


def ohmypi_api_key_env_name(entry: LLMConfigEntry, index: int) -> str:
    seed = "\0".join([
        str(index),
        config_display_name(entry),
        str(entry.cfg.get("apibase") or ""),
        str(entry.cfg.get("model") or ""),
        str(entry.cfg.get("apikey") or ""),
    ])
    digest = hashlib.sha256(seed.encode("utf-8", errors="replace")).hexdigest()[:16].upper()
    return f"GA_TUI_OMP_API_KEY_{digest}"


def ohmypi_runtime_settings_payload(default_model: str, *, approval_mode: str = "") -> dict[str, Any]:
    approval_mode = normalized_ohmypi_approval_mode(approval_mode or default_ohmypi_approval_mode())
    payload: dict[str, Any] = {
        "autoResume": False,
        "browser": {"headless": True},
        "github": {"enabled": False},
        "memory": {"backend": "local"},
        "providers": {"webSearch": "tavily"},
        "symbolPreset": "unicode",
        "task": {"maxRuntimeMs": 0},
        "todo": {"eager": "default"},
        "tools": {"approvalMode": approval_mode},
        "vault": {"enabled": False},
    }
    if default_model:
        payload["modelRoles"] = {"default": default_model}
    return payload


def positive_int_config_value(value: Any) -> int:
    try:
        number = int(str(value).strip())
    except Exception:
        return 0
    return number if number > 0 else 0


def build_ohmypi_runtime_config(*, write_files: bool = True, base_env: Optional[dict[str, str]] = None) -> OhMyPiRuntimeConfig:
    entries, mixin, _preserved, _error = load_llm_config_entries()
    default_name = str((mixin.get("llm_nos") or [""])[0] or "").strip()
    agent_dir = ohmypi_isolated_agent_dir(AGENT_HARNESS_DIR)
    provider_payloads: dict[str, Any] = {}
    runtime_models: list[OhMyPiRuntimeModel] = []
    env_overrides: dict[str, str] = {}

    for index, entry in enumerate(entries):
        cfg = entry.cfg
        api_key = str(cfg.get("apikey") or "").strip()
        api_base = str(cfg.get("apibase") or "").strip()
        model_id = str(cfg.get("model") or "").strip()
        if not api_key or not api_base or not model_id:
            continue
        api = ohmypi_model_api_for_entry(entry)
        provider_id = ohmypi_provider_id_for_entry(entry, index)
        env_key = ohmypi_api_key_env_name(entry, index)
        env_overrides[env_key] = api_key
        context_window = positive_int_config_value(cfg.get("context_win"))
        max_tokens = positive_int_config_value(cfg.get("max_tokens"))
        model_payload: dict[str, Any] = {"api": api, "id": model_id}
        if context_window > 0:
            model_payload["contextWindow"] = context_window
        if max_tokens > 0:
            model_payload["maxTokens"] = max_tokens
        provider_payloads[provider_id] = {
            "api": api,
            "apiKey": env_key,
            "baseUrl": endpoint_base(api_base) or api_base,
            "models": [model_payload],
        }
        runtime_models.append(OhMyPiRuntimeModel(
            provider=provider_id,
            model_id=model_id,
            display_name=config_display_name(entry),
            base_url=api_base,
            api=api,
            context_window=context_window,
            max_tokens=max_tokens,
        ))

    default_model = ""
    for entry, runtime_model in zip(
        [item for item in entries if str(item.cfg.get("apikey") or "").strip() and str(item.cfg.get("apibase") or "").strip() and str(item.cfg.get("model") or "").strip()],
        runtime_models,
    ):
        if default_name and config_display_name(entry) == default_name:
            default_model = runtime_model.selector
            break
    if not default_model and runtime_models:
        default_model = runtime_models[0].selector
    approval_mode = default_ohmypi_approval_mode()

    paths = {
        "agent_dir": agent_dir,
        "config_path": os.path.join(agent_dir, "config.yml"),
        "models_path": os.path.join(agent_dir, "models.yml"),
    }
    if write_files:
        paths = write_ohmypi_runtime_files(
            agent_dir=agent_dir,
            config=ohmypi_runtime_settings_payload(default_model, approval_mode=approval_mode),
            models={"providers": provider_payloads},
        )
    env = ohmypi_subprocess_env(agent_dir=agent_dir, env_overrides=env_overrides, base_env=base_env)
    return OhMyPiRuntimeConfig(
        agent_dir=paths["agent_dir"],
        env=env,
        models=runtime_models,
        default_model=default_model,
        config_path=paths["config_path"],
        models_path=paths["models_path"],
        approval_mode=approval_mode,
    )


def refresh_agent_runtime_model_config(agent: Any) -> str:
    if agent is None or not is_ohmypi_runtime_agent(agent):
        return ""
    refresh = getattr(agent, "refresh_configured_models", None)
    if not callable(refresh):
        return ""
    runtime_config = build_ohmypi_runtime_config(write_files=True)
    append_prompt_path = write_ohmypi_memory_prompt(root_dir=SHUHENG_HOME, harness_dir=AGENT_HARNESS_DIR)
    command = ohmypi_rpc_command(
        append_system_prompt=append_prompt_path,
        model=runtime_config.default_model,
        approval_mode=runtime_config.approval_mode,
    )
    refresh(runtime_config.models, env=runtime_config.env, command=command, default_model=runtime_config.default_model)
    return f"OMP runtime 模型配置已刷新（{len(runtime_config.models)} 个模型）。"


def agent_runtime_registry(*, write_memory_prompt_file: bool = True) -> RuntimeRegistry:
    requested = os.environ.get("GA_TUI_RUNTIME_PROVIDER", "ohmypi").strip() or "ohmypi"
    registry = RuntimeRegistry(default_provider_id=requested)
    registry.register(GenericAgentRuntimeAdapter(genericagent_provider_spec(
        root_dir=ROOT_DIR,
        harness_dir=AGENT_HARNESS_DIR,
        recent_models_path=LLM_RECENT_MODELS_PATH,
        schedules_path=AGENT_SCHEDULES_PATH,
    )))
    maybe_bootstrap_shuheng_legacy_state()
    ensure_shuheng_layered_memory_files()
    ohmypi_append_prompt_path = (
        write_ohmypi_memory_prompt(root_dir=SHUHENG_HOME, harness_dir=AGENT_HARNESS_DIR)
        if write_memory_prompt_file
        else ohmypi_memory_prompt_path(AGENT_HARNESS_DIR)
    )
    ohmypi_runtime_config = build_ohmypi_runtime_config(write_files=True)
    ohmypi_command = ohmypi_rpc_command(
        append_system_prompt=ohmypi_append_prompt_path,
        model=ohmypi_runtime_config.default_model,
        approval_mode=ohmypi_runtime_config.approval_mode,
    )
    registry.register(OhMyPiRuntimeAdapter(ohmypi_provider_spec(
        root_dir=ROOT_DIR,
        harness_dir=AGENT_HARNESS_DIR,
        recent_models_path=LLM_RECENT_MODELS_PATH,
        schedules_path=AGENT_SCHEDULES_PATH,
        command=ohmypi_command,
        runtime_config=ohmypi_runtime_config,
    ),
        command=ohmypi_command,
        cwd=APP_ROOT_DIR,
        env=ohmypi_runtime_config.env,
        configured_models=ohmypi_runtime_config.models,
        default_model=ohmypi_runtime_config.default_model,
        memory_candidate_sink=append_ohmypi_memory_candidate_signal,
        host_tool_definitions=ohmypi_tui_host_tool_definitions(),
        host_tool_handler=ohmypi_tui_host_tool_handler(None),
        runtime_event_sink=append_ohmypi_runtime_event,
    ))
    return registry


def runtime_registry_record() -> dict[str, Any]:
    data = agent_runtime_registry().to_record()
    data["updated_at"] = now_iso()
    data["registry_path"] = AGENT_RUNTIME_REGISTRY_PATH
    write_text_atomic(AGENT_RUNTIME_REGISTRY_PATH, json.dumps(data, ensure_ascii=False, indent=2, sort_keys=True) + "\n")
    return data


def browse_input_history(state: State, direction: int) -> bool:
    result = input_history_browse_result(
        state.input_history,
        state.input_text,
        state.input_cursor,
        state.input_history_index,
        state.input_history_draft,
        state.input_history_draft_cursor,
        direction,
    )
    if not result.consumed:
        return False
    state.input_history_index = result.history_index
    state.input_history_draft = result.draft
    state.input_history_draft_cursor = result.draft_cursor
    set_input_text(state, result.text, result.cursor)
    state.command_index = 0
    mark_dirty(state)
    return True


def new_agent(log_path: Optional[str] = None) -> Any:
    adapter = agent_runtime_registry().default()
    agent = adapter.create_agent()
    try:
        setattr(agent, "_ga_tui_runtime_provider_id", adapter.provider_id)
    except Exception:
        pass
    agent_no = next(_AGENT_COUNTER)
    thread_name = f"ga-tui-agent-{agent_no}"
    adapter.prepare_agent(agent)
    target_log_path = log_path or new_session_log_path()
    set_agent_log_path(agent, target_log_path)
    adapter.start_agent(agent, thread_name=thread_name)
    set_agent_log_path(agent, target_log_path)
    return agent


def install_interaction_hook(state: State, agent: Any) -> None:
    if agent is None:
        return
    install_tui_query_runtime(agent, state)
    if hasattr(agent, "configure_host_tools"):
        try:
            agent.configure_host_tools(
                host_tool_definitions=ohmypi_tui_host_tool_definitions(),
                host_tool_handler=ohmypi_tui_host_tool_handler(state),
            )
        except Exception:
            pass
    try:
        hooks = getattr(agent, "_turn_end_hooks", None)
        if hooks is None:
            hooks = agent._turn_end_hooks = {}

        def _hook(ctx, _state=state, _agent=agent):
            exit_reason = (ctx or {}).get("exit_reason") or {}
            if exit_reason.get("result") != "EXITED":
                return
            payload = exit_reason.get("data")
            if not isinstance(payload, dict):
                return
            if payload.get("status") != "INTERRUPT" or payload.get("intent") != "HUMAN_INTERVENTION":
                return
            request = request_payload_from_args("ask_user", payload.get("data") or {})
            if request:
                _state.ui_queue.put(("interaction", _agent, request))

        hooks["_ga_curses_interaction"] = _hook
    except Exception:
        pass


def rel_age(mtime: float) -> str:
    delta = int(time.time() - mtime)
    if delta < 60:
        return f"{delta}s"
    if delta < 3600:
        return f"{delta // 60}m"
    if delta < 86400:
        return f"{delta // 3600}h"
    return f"{delta // 86400}d"


def human_tokens(n: int) -> str:
    n = int(n or 0)
    if n < 1000:
        return str(n)
    if n < 1_000_000:
        v = n / 1000.0
        return f"{v:.1f}k" if v < 100 else f"{int(v)}k"
    v = n / 1_000_000.0
    return f"{v:.2f}M" if v < 100 else f"{int(v)}M"


def empty_token_stats_dict() -> dict[str, int]:
    return {key: 0 for key in TOKEN_STAT_KEYS}


def token_usage_file_signature() -> tuple[float, int]:
    try:
        stat = os.stat(TOKEN_USAGE_PATH)
        return (float(stat.st_mtime), int(stat.st_size))
    except OSError:
        return (0.0, -1)


def clean_token_usage_registry(raw: Any) -> dict[str, dict[str, int]]:
    if not isinstance(raw, dict):
        return {}
    session_meta = load_session_meta_registry()
    registry: dict[str, dict[str, int]] = {}
    for key, value in raw.items():
        if not isinstance(key, str) or not isinstance(value, dict):
            continue
        if is_model_response_basename(key):
            meta = session_meta.get(key, {})
            if bool(meta.get("deleted")) or bool(meta.get("hidden_subagent_log")):
                continue
            path = os.path.join(MODEL_RESPONSES_DIR, key)
            if not os.path.exists(path):
                continue
        clean = empty_token_stats_dict()
        for stat_key in TOKEN_STAT_KEYS:
            try:
                clean[stat_key] = max(0, int(value.get(stat_key, 0) or 0))
            except (TypeError, ValueError):
                clean[stat_key] = 0
        if not token_stats_has_tokens(clean):
            clean["requests"] = 0
        registry[key] = clean
    return registry


def load_token_usage_registry() -> dict[str, dict[str, int]]:
    try:
        with open(TOKEN_USAGE_PATH, encoding="utf-8") as fh:
            raw = json.load(fh)
    except Exception:
        return {}
    return clean_token_usage_registry(raw)


def save_token_usage_registry(registry: dict[str, dict[str, int]]) -> None:
    os.makedirs(os.path.dirname(TOKEN_USAGE_PATH), exist_ok=True)
    tmp = TOKEN_USAGE_PATH + ".tmp"
    with open(tmp, "w", encoding="utf-8") as fh:
        json.dump(registry, fh, ensure_ascii=False, indent=2)
    os.replace(tmp, TOKEN_USAGE_PATH)


def save_state_token_usage_registry(state: State) -> None:
    save_token_usage_registry(state.token_usage_registry)
    state.token_usage_registry_signature = token_usage_file_signature()


def prune_state_token_usage_registry(state: State) -> bool:
    clean = clean_token_usage_registry(state.token_usage_registry)
    if clean == state.token_usage_registry:
        return False
    state.token_usage_registry = clean
    try:
        save_state_token_usage_registry(state)
    except Exception as exc:
        state.last_error = f"token usage save: {type(exc).__name__}: {exc}"
    return True


def refresh_state_token_usage_registry(state: State) -> bool:
    signature = token_usage_file_signature()
    if signature == state.token_usage_registry_signature:
        return False
    state.token_usage_registry = load_token_usage_registry()
    state.token_usage_registry_signature = signature
    return True


def remove_session_token_usage(state: State, path: str) -> None:
    key = session_key(path)
    if not key:
        return
    if key in state.token_usage_registry:
        state.token_usage_registry.pop(key, None)
        try:
            save_state_token_usage_registry(state)
        except Exception as exc:
            state.last_error = f"token usage save: {type(exc).__name__}: {exc}"


def token_session_key(agent: Any) -> str:
    path = agent_log_path(agent)
    return os.path.basename(path) if path else ""


def agent_log_path_is_devnull(agent: Any) -> bool:
    path = agent_log_path(agent)
    try:
        return bool(path and normalized_path(path) == normalized_path(os.devnull))
    except Exception:
        return path == os.devnull


def token_thread_name(agent: Any) -> str:
    return str(getattr(agent, "_ga_tui_thread_name", "") or "")


def token_stats_snapshot(stats: Any) -> dict[str, int]:
    out = empty_token_stats_dict()
    if stats is None:
        return out
    for key in TOKEN_STAT_KEYS:
        try:
            out[key] = max(0, int(getattr(stats, key, 0) or 0))
        except (TypeError, ValueError):
            out[key] = 0
    return out


def token_stats_delta(now: dict[str, int], before: dict[str, int]) -> dict[str, int]:
    return {key: max(0, int(now.get(key, 0)) - int(before.get(key, 0))) for key in TOKEN_STAT_KEYS}


def token_stats_add(left: dict[str, int], right: dict[str, int]) -> dict[str, int]:
    return {key: max(0, int(left.get(key, 0)) + int(right.get(key, 0))) for key in TOKEN_STAT_KEYS}


def token_stats_has_tokens(stats: dict[str, int]) -> bool:
    return any(max(0, int(stats.get(key, 0) or 0)) > 0 for key in ("input", "output", "cache_create", "cache_read"))


def normalize_runtime_token_usage(usage: Any) -> dict[str, int]:
    if not isinstance(usage, dict):
        return empty_token_stats_dict()
    clean = empty_token_stats_dict()
    for key in TOKEN_STAT_KEYS:
        try:
            clean[key] = max(0, int(usage.get(key, 0) or 0))
        except (TypeError, ValueError):
            clean[key] = 0
    return clean


def persist_runtime_token_usage(state: State, agent: Any, usage: Any) -> bool:
    clean = normalize_runtime_token_usage(usage)
    if not token_stats_has_tokens(clean):
        return False
    key = token_session_key(agent)
    if agent_log_path_is_devnull(agent) or not key:
        return False
    refresh_state_token_usage_registry(state)
    prune_state_token_usage_registry(state)
    state.token_usage_registry[key] = token_stats_add(state.token_usage_registry.get(key, empty_token_stats_dict()), clean)
    try:
        save_state_token_usage_registry(state)
    except Exception as exc:
        state.last_error = f"token usage save: {type(exc).__name__}: {exc}"
        return False
    return True


def bind_agent_token_session(state: State, agent: Any) -> None:
    thread_name = token_thread_name(agent)
    if agent_log_path_is_devnull(agent):
        if thread_name and cost_tracker is not None:
            try:
                state.token_live_offsets[thread_name] = token_stats_snapshot(cost_tracker.get(thread_name))
            except Exception:
                state.token_live_offsets.setdefault(thread_name, empty_token_stats_dict())
        return
    key = token_session_key(agent)
    if not key or not thread_name:
        return
    state.token_usage_registry.setdefault(key, empty_token_stats_dict())
    if cost_tracker is None:
        state.token_live_offsets.setdefault(thread_name, empty_token_stats_dict())
        return
    try:
        state.token_live_offsets[thread_name] = token_stats_snapshot(cost_tracker.get(thread_name))
    except Exception:
        state.token_live_offsets.setdefault(thread_name, empty_token_stats_dict())


def reset_agent_token_session(state: State, agent: Any) -> None:
    thread_name = token_thread_name(agent)
    if thread_name and cost_tracker is not None and hasattr(cost_tracker, "reset"):
        try:
            cost_tracker.reset(thread_name)
        except Exception:
            pass
    if thread_name:
        state.token_live_offsets.pop(thread_name, None)
    bind_agent_token_session(state, agent)


def persist_agent_token_usage(state: State, agent: Any) -> bool:
    refresh_state_token_usage_registry(state)
    prune_state_token_usage_registry(state)
    key = token_session_key(agent)
    thread_name = token_thread_name(agent)
    if not thread_name or cost_tracker is None:
        return False
    try:
        current = token_stats_snapshot(cost_tracker.get(thread_name))
    except Exception:
        return False
    if agent_log_path_is_devnull(agent) or not key:
        state.token_live_offsets[thread_name] = current
        return False
    offset = state.token_live_offsets.get(thread_name, empty_token_stats_dict())
    delta = token_stats_delta(current, offset)
    if not any(delta.values()):
        return False
    state.token_usage_registry[key] = token_stats_add(state.token_usage_registry.get(key, empty_token_stats_dict()), delta)
    state.token_live_offsets[thread_name] = current
    try:
        save_state_token_usage_registry(state)
    except Exception as exc:
        state.last_error = f"token usage save: {type(exc).__name__}: {exc}"
        return False
    return True


def persist_all_token_usage(state: State) -> None:
    refresh_state_token_usage_registry(state)
    prune_state_token_usage_registry(state)
    seen: set[int] = set()
    for agent in [
        state.agent,
        *(bg.agent for bg in state.background_sessions.values()),
        *(sub.agent for sub in state.subagents.values() if sub.agent is not None),
    ]:
        if agent is None or id(agent) in seen:
            continue
        seen.add(id(agent))
        persist_agent_token_usage(state, agent)


def session_token_stats(state: State, agent: Any):
    if cost_tracker is None:
        return None
    key = token_session_key(agent)
    if not key:
        return None
    base = state.token_usage_registry.get(key, empty_token_stats_dict())
    thread_name = token_thread_name(agent)
    delta = empty_token_stats_dict()
    live = None
    if thread_name:
        try:
            live = cost_tracker.get(thread_name)
            current = token_stats_snapshot(live)
            offset = state.token_live_offsets.get(thread_name, empty_token_stats_dict())
            delta = token_stats_delta(current, offset)
        except Exception:
            live = None
    total = token_stats_add(base, delta)
    stats = cost_tracker.TokenStats()
    for stat_key, value in total.items():
        setattr(stats, stat_key, value)
    if live is not None:
        stats.last_input = getattr(live, "last_input", 0)
        stats.last_output = getattr(live, "last_output", 0)
    return stats


def host_from_url(url: str) -> str:
    url = (url or "").strip()
    if not url:
        return ""
    try:
        parsed = urllib.parse.urlparse(url if "://" in url else "https://" + url)
        return parsed.netloc or parsed.path
    except Exception:
        return url


def current_model_lines(state: State, width: int) -> list[tuple[str, int]]:
    display_agent = effective_model_display_agent(state)
    lines: list[tuple[str, int]] = [("CURRENT MODEL", cp(7) | curses.A_BOLD)]
    if display_agent is not state.agent:
        lines = [("SUBAGENT MODEL", cp(7) | curses.A_BOLD)]
    backend = None
    try:
        backend = display_agent.llmclient.backend
    except Exception:
        backend = None
    provider = model = base = ""
    if backend is not None:
        provider = str(getattr(backend, "name", "") or "")
        model = str(getattr(backend, "model", "") or "")
        base = host_from_url(str(getattr(backend, "api_base", "") or getattr(backend, "apibase", "") or ""))
    if not provider:
        try:
            provider = str(display_agent.get_llm_name(model=False))
        except Exception:
            provider = "unknown"
    if not model:
        try:
            model = str(display_agent.get_llm_name(model=True))
        except Exception:
            model = "unknown"
    lines.append((f"provider {provider}", cp(2)))
    lines.append((f"model {model}", cp(1)))
    if base:
        lines.append((f"base {base}", cp(1)))
    snapshotter = getattr(display_agent, "model_sync_snapshot", None)
    if callable(snapshotter):
        try:
            sync = snapshotter()
        except Exception:
            sync = {}
        status = str((sync or {}).get("status") or "")
        pending = str((sync or {}).get("pending_selector") or "")
        error = str((sync or {}).get("error") or "")
        if status in {"pending", "failed"}:
            sync_text = f"sync {status}"
            if pending:
                sync_text += f" {pending}"
            if error:
                sync_text += f" {error}"
            lines.append((sync_text, cp(3 if status == "pending" else 4)))
    return [(truncate_cells(text, width - 2), attr) for text, attr in lines]


def current_token_lines(state: State, width: int) -> list[tuple[str, int]]:
    native_usage = ohmypi_native_context_usage(state.agent)
    if native_usage and (native_usage.get("tokens") or native_usage.get("contextWindow")):
        tokens = int(native_usage.get("tokens") or 0)
        context_window = int(native_usage.get("contextWindow") or 0)
        percent = float(native_usage.get("percent") or 0.0)
        if percent <= 0 and tokens > 0 and context_window > 0:
            percent = tokens / context_window * 100.0
        lines: list[tuple[str, int]] = [("TOKEN USAGE", cp(7) | curses.A_BOLD)]
        if context_window > 0:
            lines.append((f"ctx {human_tokens(tokens)}/{human_tokens(context_window)}  {percent:.0f}%", cp(2)))
        else:
            lines.append((f"ctx {human_tokens(tokens)}", cp(2)))
        message_count = int(getattr(state.agent, "native_message_count", 0) or 0)
        if message_count > 0:
            lines.append((f"omp msgs {message_count}", cp(1)))
        if cost_tracker is not None:
            refresh_state_token_usage_registry(state)
            prune_state_token_usage_registry(state)
            stats = session_token_stats(state, state.agent)
            if stats is not None and stats.total_tokens() > 0:
                lines.append((f"total {human_tokens(stats.total_tokens())}  req {stats.requests}", cp(1)))
        return [(truncate_cells(text, width - 2), attr) for text, attr in lines]
    if cost_tracker is None:
        return [("TOKEN USAGE", cp(7) | curses.A_BOLD), ("tracker unavailable", cp(5))]
    refresh_state_token_usage_registry(state)
    prune_state_token_usage_registry(state)
    stats = session_token_stats(state, state.agent)
    if stats is None:
        return [("TOKEN USAGE", cp(7) | curses.A_BOLD), ("no data", cp(1))]

    total = stats.total_tokens()
    input_side = stats.total_input_side()
    lines: list[tuple[str, int]] = [
        ("TOKEN USAGE", cp(7) | curses.A_BOLD),
        (f"total {human_tokens(total)}", cp(2)),
        (f"in {human_tokens(input_side)}  out {human_tokens(stats.output)}", cp(2)),
    ]
    cache = stats.cache_read + stats.cache_create
    if cache:
        lines.append((f"cache {human_tokens(cache)}  hit {stats.cache_hit_rate():.0f}%", cp(1)))
    try:
        backend = state.agent.llmclient.backend
        cap = cost_tracker.context_window_chars(backend)
        used = cost_tracker.current_input_chars(backend)
    except Exception:
        cap = used = 0
    if cap > 0:
        pct = min(100, max(0, int(used / cap * 100)))
        lines.append((f"ctx {pct}%  req {stats.requests}", cp(1)))
    else:
        lines.append((f"req {stats.requests}", cp(1)))
    return [(truncate_cells(text, width - 2), attr) for text, attr in lines]


def current_status_panel_lines(state: State, width: int) -> list[tuple[str, int]]:
    lines = current_model_lines(state, width)
    lines.append(("", cp(1)))
    lines.extend(current_token_lines(state, width))
    lines.append((truncate_cells(secret_status_text(state), width - 2), cp(7) if state.secret_vault.unlocked else cp(1)))
    return lines[:TOKEN_PANEL_H - 1]


def load_history(state: State, force: bool = False) -> bool:
    if state.secret_vault.unlocked or state.secret_vault.pending_action:
        state.history = []
        state.history_names = {}
        state.history_descriptions = {}
        return False
    maybe_bootstrap_shuheng_legacy_state()
    now = time.time()
    if not force and now - state.history_loaded_at < 10:
        return False
    try:
        state.session_meta = load_session_meta_registry()
        session_rows, meta_changed = cached_session_rows(state, exclude_pid=os.getpid())
        history: list[tuple[str, float, str, int]] = []
        descriptions: dict[str, str] = {}
        for path, last_user_at, preview, rounds, desc in session_rows:
            meta = session_meta_for(state, path)
            if bool(meta.get("deleted")):
                continue
            archived = bool(meta.get("archived"))
            if archived != state.show_archived:
                continue
            category = session_category_label(meta)
            filter_kind = system_session_category(state.session_filter_category)
            if state.session_filter_category and not filter_kind and category_key(category) != category_key(state.session_filter_category):
                continue
            history.append((path, last_user_at, preview, rounds))
            descriptions[path] = desc
        history.sort(key=lambda item: (not bool(session_meta_for(state, item[0]).get("pinned")), -item[1]))
        names: dict[str, str] = {}
        if session_names is not None:
            try:
                registry = session_names._load()
            except Exception:
                registry = {}
            for path, _mtime, preview, _rounds in history:
                name = registry.get(os.path.basename(path), "")
                if is_process_only_session_title(name):
                    name = ""
                if not name:
                    name = preview
                names[path] = compact_title(name, 80)
        if meta_changed:
            save_session_meta_registry(state.session_meta)
        changed = (
            history != state.history
            or names != state.history_names
            or descriptions != state.history_descriptions
        )
        state.history = history
        state.history_names = names
        state.history_descriptions = descriptions
        state.history_loaded_at = now
        return changed
    except Exception as exc:
        state.last_error = f"history: {type(exc).__name__}: {exc}"
        state.dirty = True
        return False


def history_name(state: State, path: str) -> str:
    return state.history_names.get(path, "")


def clear_history_ui_state(state: State) -> None:
    state.history_ui_path = ""
    state.history_ui_loaded_rounds = 0
    state.history_ui_total_rounds = 0
    state.history_ui_message_count = 0
    state.history_ui_loading = False
    state.history_ui_token += 1
    state.session_popup_path = ""
    state.session_popup_anchor = None
    state.session_popup_rect = None


def cancel_normal_history_restore(state: State) -> None:
    state.restore_token += 1
    clear_history_ui_state(state)


def rename_current_session(state: State, raw_name: str, source: str = "manual") -> str:
    name = compact_title(raw_name, 80)
    if not name:
        return "名称不能为空。"
    if state.temporary_session:
        state.current_title = name
        mark_dirty(state)
        return f"当前临时会话已命名为: {name}；仅本次界面生效，不会持久化。"
    persist_msg = ""
    title_source = title_source_for_rename(source)
    if session_names is not None:
        try:
            path = getattr(state.agent, "log_path", "")
            if path:
                if title_source == "ai" and str(session_meta_for(state, path).get("title_source") or "") == "manual":
                    return "手动标题已保留，AI 改名已跳过。"
                session_names.set_name(path, name)
                set_session_meta_fields(
                    state,
                    path,
                    title_source=title_source,
                    title_signature="",
                    title_updated_at=time.time(),
                )
                persist_msg = "已持久化。"
            else:
                persist_msg = "当前会话暂无日志路径，仅本次界面生效。"
        except Exception as exc:
            persist_msg = f"持久化失败: {type(exc).__name__}: {exc}"
    else:
        persist_msg = "session_names 模块不可用，仅本次界面生效。"
    state.current_title = name
    if load_history(state, force=True):
        state.dirty = True
    mark_dirty(state)
    return f"当前会话已命名为: {name}；{persist_msg}"


def session_category_label(meta: dict[str, Any]) -> str:
    return compact_category(str(meta.get("category") or "")) or "未分类"


def category_registry(state: State) -> dict[str, dict[str, Any]]:
    raw = state.session_meta.get("__categories__", {})
    return raw if isinstance(raw, dict) else {}


def category_meta_for(state: State, label: str) -> dict[str, Any]:
    raw = category_registry(state).get(category_key(label), {})
    return raw if isinstance(raw, dict) else {}


def set_category_meta_fields(state: State, label: str, **fields: Any) -> None:
    key = category_key(label)
    if not key:
        return
    registry = dict(category_registry(state))
    entry = dict(registry.get(key, {}))
    entry.setdefault("name", category_filter_label(label) or "未分类")
    for field_name, value in fields.items():
        if value in (None, ""):
            entry.pop(field_name, None)
        else:
            entry[field_name] = value
    registry[key] = entry
    state.session_meta["__categories__"] = registry
    save_session_meta_registry(state.session_meta)


def category_key(raw: str) -> str:
    label = compact_category(raw)
    return label.casefold() if label else "__uncategorized__"


def system_session_category(raw: str) -> str:
    key = category_key(raw)
    if key in {category_key(PINNED_SESSION_LABEL), "pinned", "pin", "置顶"}:
        return "pinned"
    if key in {category_key(RECENT_SESSION_LABEL), "recent", "最近", "最近打开"}:
        return "recent"
    return ""


def category_sort_key(label: str) -> tuple[int, str, str]:
    key = category_key(label)
    if key == "__uncategorized__":
        return (1, "", "")
    normalized = compact_category(label).casefold()
    first = normalized[:1]
    return (0, locale.strxfrm(first), locale.strxfrm(normalized))


def category_filter_label(raw: str) -> str:
    raw = (raw or "").strip()
    if not raw or raw.lower() in {"off", "all", "clear", "none", "全部"}:
        return ""
    return compact_category(raw) or "未分类"


def set_session_filter(state: State, raw: str) -> str:
    label = category_filter_label(raw)
    state.session_filter_category = label
    state.sidebar_scroll = 0
    load_history(state, force=True)
    mark_dirty(state)
    return f"已按分类筛选：{label}" if label else "已关闭分类筛选。"


def category_counts_for_view(state: State) -> list[tuple[str, int]]:
    state.session_meta = load_session_meta_registry()
    session_rows, meta_changed = cached_session_rows(state, exclude_pid=os.getpid())
    if meta_changed:
        save_session_meta_registry(state.session_meta)
    counts: dict[str, list[Any]] = {}
    pinned_count = 0
    recent_count = 0
    for path, _mtime, _preview, _rounds, _desc in session_rows:
        meta = session_meta_for(state, path)
        if bool(meta.get("deleted")):
            continue
        if bool(meta.get("archived")) != state.show_archived:
            continue
        pinned = bool(meta.get("pinned"))
        if pinned:
            pinned_count += 1
        if not pinned and float(_mtime or 0.0) > 0:
            recent_count += 1
        label = session_category_label(meta)
        key = category_key(label)
        if key not in counts:
            counts[key] = [label, 0]
        counts[key][1] += 1
    result: list[tuple[str, int]] = []
    if pinned_count:
        result.append((PINNED_SESSION_LABEL, pinned_count))
    if recent_count:
        result.append((RECENT_SESSION_LABEL, min(RECENT_SESSION_LIMIT, recent_count)))
    result.extend([
        (str(label), int(count))
        for label, count in sorted(
            counts.values(),
            key=lambda item: (*category_sort_key(str(item[0])), -int(item[1])),
        )
    ])
    return result


def format_category_counts(state: State) -> str:
    counts = category_counts_for_view(state)
    if not counts:
        return "当前视图没有分类。"
    active = f"当前筛选：{state.session_filter_category}" if state.session_filter_category else "当前筛选：全部"
    lines = [active, "分类列表："]
    for label, count in counts:
        desc = compact_description(str(category_meta_for(state, label).get("description") or ""))
        suffix = f" - {desc}" if desc else ""
        lines.append(f"- {label}: {count}{suffix}")
    return "\n".join(lines)


def parse_history_curator_args(raw: str) -> dict[str, Any]:
    text = (raw or "").strip()
    limit = 12
    for pattern in (r"(?:--limit|limit|限制)\s*[=:]?\s*(\d+)", r"\b(\d{1,3})\s*$"):
        match = re.search(pattern, text, re.I)
        if match:
            try:
                limit = int(match.group(1))
            except ValueError:
                limit = 12
            text = (text[:match.start()] + text[match.end():]).strip()
            break
    limit = max(1, min(40, limit))
    lowered = text.lower()
    if not text or lowered in {"recent", "最近"}:
        return {"mode": "recent", "query": "", "limit": limit}
    if lowered in {"all", "全部"}:
        return {"mode": "all", "query": "", "limit": limit}
    if lowered in {"pinned", "pin", "置顶"}:
        return {"mode": "pinned", "query": "", "limit": limit}
    cat_match = re.match(r"^(?:cat|category|分类)[:：\s]+(.+)$", text, re.I)
    if cat_match:
        return {"mode": "category", "query": category_filter_label(cat_match.group(1)), "limit": limit}
    search_match = re.match(r"^(?:search|q|查找)[:：\s]+(.+)$", text, re.I)
    if search_match:
        return {"mode": "search", "query": clean_text(search_match.group(1)).strip(), "limit": limit}
    return {"mode": "category", "query": category_filter_label(text), "limit": limit}


def history_curator_rows(state: State, raw_args: str = "") -> tuple[dict[str, Any], list[dict[str, Any]]]:
    scope = parse_history_curator_args(raw_args)
    load_history(state, force=True)
    entries = list(enumerate(state.history, 1))
    mode = str(scope.get("mode") or "recent")
    query = str(scope.get("query") or "")
    if mode == "category" and query:
        entries = [
            (idx, item)
            for idx, item in entries
            if category_key(session_category_label(session_meta_for(state, item[0]))) == category_key(query)
        ]
    elif mode == "pinned":
        entries = [(idx, item) for idx, item in entries if session_meta_for(state, item[0]).get("pinned")]
    elif mode == "search" and query:
        needle = query.casefold()
        entries = [
            (idx, item)
            for idx, item in entries
            if needle in " ".join([
                history_name(state, item[0]),
                item[2],
                state.history_descriptions.get(item[0], ""),
                session_category_label(session_meta_for(state, item[0])),
                os.path.basename(item[0]),
            ]).casefold()
        ]
    limit = int(scope.get("limit") or 12)
    if mode == "recent":
        entries = entries[:limit]
    else:
        entries = entries[:limit]
    rows: list[dict[str, Any]] = []
    for idx, (path, mtime, preview, rounds) in entries:
        meta = session_meta_for(state, path)
        title = compact_title(history_name(state, path) or preview or os.path.basename(path), 90)
        category = session_category_label(meta)
        description = compact_description(state.history_descriptions.get(path, "") or str(meta.get("description") or ""), 220)
        stable_id = session_stable_id(path)
        source_path = str(meta.get("source_path") or path)
        rows.append({
            "index": idx,
            "stable_id": stable_id,
            "title": title,
            "category": category,
            "rounds": int(rounds or 0),
            "age": rel_age(float(mtime or time.time())),
            "activity_at": float(mtime or 0.0),
            "pinned": bool(meta.get("pinned")),
            "archived": bool(meta.get("archived")),
            "source_missing": bool(meta.get("source_missing") or meta.get("archive_backed")),
            "source_path": source_path,
            "description": description,
            "evidence_ref": f"session://{stable_id}",
        })
    return scope, rows


def format_history_curator_index(scope: dict[str, Any], rows: list[dict[str, Any]]) -> str:
    mode = str(scope.get("mode") or "recent")
    query = str(scope.get("query") or "")
    lines = [
        "# Shuheng History Curation Index",
        "",
        f"- scope: {mode}{':' + query if query else ''}",
        f"- returned_sessions: {len(rows)}",
        "- disclosure_level: index+cached_summary_only",
        "",
        "## Sessions",
    ]
    for row in rows:
        flags = []
        if row.get("pinned"):
            flags.append("pinned")
        if row.get("archived"):
            flags.append("archived")
        if row.get("source_missing"):
            flags.append("archive-backed")
        flag_text = f" flags={','.join(flags)}" if flags else ""
        lines.append(
            f"- S{int(row['index']):02d} id:{row['stable_id']} "
            f"category={row['category']} rounds={row['rounds']} age={row['age']}{flag_text}"
        )
        lines.append(f"  title: {row['title']}")
        if row.get("description"):
            lines.append(f"  cached_summary: {row['description']}")
        lines.append(f"  evidence_ref: {row['evidence_ref']}")
        lines.append(f"  source_path: {row['source_path']}")
    return "\n".join(lines)


def history_curator_skill_prompt(state: State, raw_args: str = "") -> tuple[str, str, list[dict[str, Any]]]:
    scope, rows = history_curator_rows(state, raw_args)
    index_text = format_history_curator_index(scope, rows)
    artifact_ref = write_harness_artifact(
        "history-curation-index",
        f"{scope.get('mode', 'recent')}-{scope.get('query', '') or 'default'}",
        index_text,
        provenance={
            "generated_by": "orchestrator.main",
            "source": "history_curator_skill",
            "scope": scope,
            "disclosure_level": "index+cached_summary_only",
        },
    )
    category_lines = [
        f"- {label}: {count}{' - ' + compact_description(str(category_meta_for(state, label).get('description') or '')) if category_meta_for(state, label).get('description') else ''}"
        for label, count in category_counts_for_view(state)
    ]
    prompt = f"""[Shuheng History Curator Skill]
Objective: Curate Shuheng history into category digests, memory candidates, and long-term subagent recommendations using progressive disclosure.

Progressive disclosure protocol:
1. Start only from the index and cached summaries below. Do not assume raw session content has been read.
2. If more evidence is needed, name at most 3 stable ids under "Needs Deeper Disclosure" with the reason. Only then should raw session files be opened in a later step.
3. Treat raw sessions as L4 archive evidence. Do not copy long conversations into the answer.
4. Do not write long-term memory directly. Output memory candidates only; they must later go through Shuheng's governed memory_candidate approval path.
5. Do not create persistent subagents directly. Recommend them only when a repeated long-running responsibility is clear.

Nested subskills to run mentally:
- history-classifier: check whether existing categories fit; suggest category renames/descriptions if useful.
- category-digest: summarize durable themes per category from cached summaries only.
- memory-curator: extract stable facts/preferences/SOPs that would change future behavior; reject temporary chatter.
- subagent-recommender: detect repeated responsibilities that deserve a persistent subagent; include role, profile, tools boundary, and why reuse beats one-off chat.

Output format:
1. Category Digest
2. Memory Candidates (candidate only, with type, target scope, statement, evidence_refs, confidence)
3. Archive Only / Do Not Memorize
4. Persistent Subagent Recommendations (recommendation only, no creation)
5. Needs Deeper Disclosure

Current category counts:
{chr(10).join(category_lines) or "- (none)"}

Index artifact: {artifact_ref}

{index_text}
[/Shuheng History Curator Skill]"""
    return prompt, artifact_ref, rows


def start_history_curator_skill(state: State, raw_args: str, visible_text: str) -> bool:
    prompt, _artifact_ref, rows = history_curator_skill_prompt(state, raw_args)
    if not rows:
        add_system(state, "没有可策展的历史会话；可以先退出筛选或切换 /archived。")
        return False
    return start_main_agent_task(
        state,
        prompt,
        source="user:history_curator_skill",
        visible_user_text=visible_text,
        remember_user=True,
        clear_history=True,
        runtime_context_mode="lean",
    )


def rename_category(state: State, old: str, new: str) -> str:
    old_label = category_filter_label(old)
    new_label = category_filter_label(new)
    if not old_label or not new_label:
        return "Usage: /catname <old> <new>"
    changed = 0
    old_key = category_key(old_label)
    for key, meta in list(state.session_meta.items()):
        if not isinstance(meta, dict) or key == "__categories__":
            continue
        if category_key(str(meta.get("category") or "")) == old_key:
            entry = dict(meta)
            entry["category"] = new_label
            entry.setdefault("category_source", "manual")
            state.session_meta[key] = entry
            changed += 1
    registry = dict(category_registry(state))
    old_meta = dict(registry.pop(old_key, {}))
    old_meta["name"] = new_label
    registry[category_key(new_label)] = old_meta
    state.session_meta["__categories__"] = registry
    save_session_meta_registry(state.session_meta)
    load_history(state, force=True)
    mark_dirty(state)
    return f"已重命名分类：{old_label} -> {new_label}，影响 {changed} 个会话。"


def set_category_description(state: State, raw_category: str, raw_description: str) -> str:
    label = category_filter_label(raw_category)
    description = compact_description(raw_description)
    if not label or not description:
        return "Usage: /catdesc <category> <description>"
    set_category_meta_fields(state, label, description=description, source="manual", updated_at=time.time())
    mark_dirty(state)
    return f"已设置分类简介：{label}"


def set_category_collapsed(state: State, raw: str, collapsed: bool) -> str:
    raw = (raw or "").strip()
    counts = category_counts_for_view(state)
    if not raw:
        return "Usage: /collapse <category|all> 或 /expand <category|all>"
    if raw.lower() in {"all", "全部", "*"}:
        keys = {category_key(label) for label, _count in counts}
        if collapsed:
            state.collapsed_categories.update(keys)
            result = "已折叠所有分类。"
        else:
            state.collapsed_categories.difference_update(keys)
            result = "已展开所有分类。"
        mark_dirty(state)
        return result
    target = category_key(raw)
    if collapsed:
        state.collapsed_categories.add(target)
        result = f"已折叠分类：{category_filter_label(raw) or '未分类'}"
    else:
        state.collapsed_categories.discard(target)
        result = f"已展开分类：{category_filter_label(raw) or '未分类'}"
    mark_dirty(state)
    return result


def toggle_category_collapsed(state: State, raw: str) -> str:
    key = category_key(raw)
    if key in state.collapsed_categories:
        state.collapsed_categories.discard(key)
        result = f"已展开分类：{category_filter_label(raw) or '未分类'}"
    else:
        state.collapsed_categories.add(key)
        result = f"已折叠分类：{category_filter_label(raw) or '未分类'}"
    mark_dirty(state)
    return result


def current_session_path(state: State) -> str:
    if state.temporary_session:
        return ""
    return str(getattr(state.agent, "log_path", "") or "")


def is_current_session_path(state: State, path: str) -> bool:
    return bool(path) and normalized_path(path) == normalized_path(current_session_path(state))


def background_session_key_for_path(state: State, path: str) -> str:
    target = normalized_path(path)
    if not target:
        return ""
    for key, bg in state.background_sessions.items():
        if normalized_path(getattr(bg.agent, "log_path", "")) == target:
            return key
    return ""


def reset_backend_memory_no_snapshot(agent: Any) -> None:
    reset_agent_runtime_context_no_snapshot(agent)


def clear_active_session_after_meta_action(state: State, message: str, *, persist_current_tokens: bool = True) -> None:
    if persist_current_tokens:
        persist_agent_token_usage(state, state.agent)
    reset_backend_memory_no_snapshot(state.agent)
    set_agent_log_path(state.agent, new_session_log_path())
    reset_agent_token_session(state, state.agent)
    state.messages.clear()
    state.current_title = "main"
    state.selected_session = MAIN_HOME_SESSION_KEY
    state.temporary_session = False
    state.status = "idle"
    state.active_task_id = None
    state.active_task_source = ""
    state.active_stream_target = None
    clear_active_plan_state(state)
    state.pending_interaction = None
    clear_history_ui_state(state)
    set_input_text(state, "")
    state.last_error = message
    load_history(state, force=True)
    mark_messages_changed(state)


def session_title_for_path(state: State, path: str) -> str:
    for item_path, _mtime, preview, _rounds in state.history:
        if normalized_path(item_path) == normalized_path(path):
            return compact_title(history_name(state, item_path) or preview or os.path.basename(path or ""), 80) or "当前会话"
    return compact_title(history_name(state, path) or os.path.basename(path or ""), 80) or "当前会话"


def session_stable_id(path: str) -> str:
    base = os.path.basename(path or "")
    match = re.search(r"model_responses_(?:snapshot_)?(.+?)\.txt$", base)
    return match.group(1) if match else base


def all_resolvable_session_paths(state: State) -> list[str]:
    state.session_meta = load_session_meta_registry()
    session_rows, meta_changed = cached_session_rows(state, exclude_pid=os.getpid())
    if meta_changed:
        save_session_meta_registry(state.session_meta)
    paths: list[str] = []
    seen: set[str] = set()
    for path, _mtime, _preview, _rounds, _desc in session_rows:
        key = session_key(path)
        if bool(state.session_meta.get(key, {}).get("deleted")):
            continue
        norm = normalized_path(path)
        if norm not in seen:
            paths.append(path)
            seen.add(norm)
    current = current_session_path(state)
    if current:
        norm = normalized_path(current)
        if norm not in seen:
            paths.insert(0, current)
    return paths


def target_matches_session_id(path: str, target: str) -> bool:
    base = os.path.basename(path or "")
    stable = session_stable_id(path)
    target = (target or "").strip()
    normalized = re.sub(r"^(?:id:|#)", "", target, flags=re.I)
    target_digits = "".join(re.findall(r"\d+", normalized))
    return target == base or normalized == stable or normalized == base or (bool(target_digits) and target_digits == stable)


def resolve_stable_session_target(state: State, target: str) -> tuple[Optional[str], str]:
    matches = [path for path in all_resolvable_session_paths(state) if target_matches_session_id(path, target)]
    if len(matches) == 1:
        return matches[0], ""
    if len(matches) > 1:
        return None, f"稳定 id 匹配到多个会话：{target}"
    return None, ""


def session_target_matches_expected(state: State, path: str, expected: str) -> bool:
    expected = compact_title(expected, 40).casefold()
    if not expected:
        return True
    title = compact_title(session_title_for_path(state, path), 40).casefold()
    base = os.path.basename(path).casefold()
    return expected in title or title in expected or expected in base


def resolve_session_target(
    state: State,
    raw_target: str = "",
    *,
    allow_view_index: bool = True,
    expected_title: str = "",
) -> tuple[Optional[str], str]:
    target = (raw_target or "").strip()
    if not target or target.lower() in {"current", "now", "当前"}:
        path = current_session_path(state)
        return (path, "") if path else (None, "当前会话没有日志路径。")
    if target.lower() == "selected" and isinstance(state.selected_session, str) and state.selected_session != "main" and not is_home_session_key(state.selected_session):
        return state.selected_session, ""
    if os.path.isabs(target) and os.path.exists(target):
        return target, ""
    stable_path, stable_error = resolve_stable_session_target(state, target)
    if stable_path or stable_error:
        return stable_path, stable_error
    m = re.fullmatch(r"[sS]?(\d+)", target)
    if m:
        if not allow_view_index and not expected_title:
            return None, f"拒绝使用相对编号 {target}：请让 agent 使用 /sessions 的稳定 id:xxxxxx 或文件名。"
        idx = int(m.group(1)) - 1
        if 0 <= idx < len(state.history):
            path = state.history[idx][0]
            if expected_title and not session_target_matches_expected(state, path, expected_title):
                actual = session_title_for_path(state, path)
                return None, f"编号 {target} 标题不匹配：期望「{expected_title}」，实际「{actual}」。"
            return path, ""
        return None, f"索引越界: 1-{len(state.history)}"
    target_l = target.lower()
    matches = [
        path for path, _mtime, first, _rounds in state.history
        if (history_name(state, path) or first or os.path.basename(path)).lower().startswith(target_l)
    ]
    if len(matches) == 1:
        return matches[0], ""
    if len(matches) > 1:
        return None, "匹配到多个会话，请用左侧编号。"
    return None, "找不到会话，请用 current 或左侧编号。"


def unique_trash_path(path: str) -> str:
    os.makedirs(SESSION_TRASH_DIR, exist_ok=True)
    base = os.path.basename(path)
    stamp = time.strftime("%Y%m%d-%H%M%S")
    candidate = os.path.join(SESSION_TRASH_DIR, f"{stamp}-{base}")
    idx = 1
    while os.path.exists(candidate):
        candidate = os.path.join(SESSION_TRASH_DIR, f"{stamp}-{idx}-{base}")
        idx += 1
    return candidate


def apply_session_operation(
    state: State,
    action: str,
    target: str = "",
    value: str = "",
    source: str = "TUI",
    *,
    allow_view_index: bool = True,
    expected_title: str = "",
) -> str:
    action = (action or "").strip().lower().replace("-", "_")
    if state.secret_vault.unlocked and action not in {"hide_archived", "archived_off"}:
        return "Secret Vault 已解锁：普通会话操作已隔离，请先 /lock。"
    if action in {"filter", "set_filter", "filter_category"}:
        raw = value or (target if target not in {"", "current"} else "")
        return set_session_filter(state, raw)
    if action in {"clear_filter", "filter_off"}:
        return set_session_filter(state, "off")
    if action in {"collapse", "collapse_category"}:
        raw = value or (target if target not in {"", "current"} else "")
        return set_category_collapsed(state, raw, True)
    if action in {"expand", "expand_category"}:
        raw = value or (target if target not in {"", "current"} else "")
        return set_category_collapsed(state, raw, False)
    if action in {"toggle_category", "toggle_collapse"}:
        raw = value or (target if target not in {"", "current"} else "")
        if not raw:
            return "缺少分类名。"
        return toggle_category_collapsed(state, raw)
    if action in {"show_archived", "archived_on"}:
        state.show_archived = True
        load_history(state, force=True)
        mark_dirty(state)
        return "已切到归档会话视图。"
    if action in {"hide_archived", "archived_off"}:
        state.show_archived = False
        load_history(state, force=True)
        mark_dirty(state)
        return "已切回普通会话视图。"
    if action in {"toggle_archived", "archived"}:
        state.show_archived = not state.show_archived
        load_history(state, force=True)
        mark_dirty(state)
        return "已切到归档会话视图。" if state.show_archived else "已切回普通会话视图。"

    path, error = resolve_session_target(state, target, allow_view_index=allow_view_index, expected_title=expected_title)
    if error:
        return error
    if not path:
        return "找不到目标会话。"
    title = session_title_for_path(state, path)
    if action in {"pin", "pinned"}:
        set_session_meta_fields(state, path, pinned=True)
        load_history(state, force=True)
        mark_dirty(state)
        return f"已置顶会话：{title}"
    if action in {"unpin", "unpinned"}:
        set_session_meta_fields(state, path, pinned=False)
        load_history(state, force=True)
        mark_dirty(state)
        return f"已取消置顶：{title}"
    if action in {"category", "categorize", "set_category"}:
        category = compact_category(value)
        category_source = "manual" if source in {"TUI"} or source.startswith("/") else source
        set_session_meta_fields(state, path, category=category, category_source=category_source)
        load_history(state, force=True)
        mark_dirty(state)
        return f"已设置分类：{title} -> {category or '未分类'}"
    if action in {"archive"}:
        if is_current_session_path(state, path) and state.status in {"running", "aborting"}:
            return "当前会话还在运行，不能归档；先 Ctrl+C 中止或等它完成。"
        set_session_meta_fields(state, path, archived=True)
        if is_current_session_path(state, path):
            clear_active_session_after_meta_action(state, f"已归档当前会话：{title}")
        else:
            load_history(state, force=True)
            mark_dirty(state)
        return f"已归档会话：{title}"
    if action in {"unarchive", "restore_archive"}:
        set_session_meta_fields(state, path, archived=False, deleted=False)
        load_history(state, force=True)
        mark_dirty(state)
        return f"已取消归档：{title}"
    if action in {"delete", "remove"}:
        if is_current_session_path(state, path) and state.status in {"running", "aborting"}:
            return "当前会话还在运行，不能删除；先 Ctrl+C 中止或等它完成。"
        if not os.path.exists(path):
            set_session_meta_fields(state, path, deleted=True, deleted_at=time.time())
            remove_session_token_usage(state, path)
            load_history(state, force=True)
            return f"会话文件不存在，已从列表隐藏：{title}"
        trash_path = unique_trash_path(path)
        try:
            shutil.move(path, trash_path)
        except Exception as exc:
            return f"删除失败: {type(exc).__name__}: {exc}"
        set_session_meta_fields(state, path, deleted=True, archived=True, trash_path=trash_path, deleted_at=time.time())
        remove_session_token_usage(state, path)
        if session_names is not None:
            try:
                session_names.set_name(path, "")
            except Exception:
                pass
        if is_current_session_path(state, path):
            clear_active_session_after_meta_action(state, f"已删除当前会话到回收站：{title}", persist_current_tokens=False)
        else:
            load_history(state, force=True)
            mark_dirty(state)
        return f"已删除到回收站：{title}"
    return f"{source}: 未知会话操作 {action}"


def title_source_for_rename(source: str) -> str:
    return "manual" if source in {"", "manual", "TUI"} or source.startswith("/") else "ai"


def rename_session_path(state: State, path: str, raw_name: str, source: str = "manual") -> str:
    name = compact_title(raw_name, 80)
    if not name:
        return "名称不能为空。"
    if is_current_session_path(state, path):
        return rename_current_session(state, name, source=source)
    if session_names is None:
        return "session_names 模块不可用，无法持久化历史会话名称。"
    title_source = title_source_for_rename(source)
    if title_source == "ai" and str(session_meta_for(state, path).get("title_source") or "") == "manual":
        return "手动标题已保留，AI 改名已跳过。"
    try:
        session_names.set_name(path, name)
        set_session_meta_fields(
            state,
            path,
            title_source=title_source,
            title_signature="",
            title_updated_at=time.time(),
        )
        if load_history(state, force=True):
            state.dirty = True
        return f"已命名会话：{name}"
    except Exception as exc:
        return f"命名失败: {type(exc).__name__}: {exc}"


def display_prompt_for_subagent_task(prompt: str) -> str:
    prompt = clean_text((prompt or "").strip())
    payload = agenttask_payload_from_prompt(prompt)
    if not payload:
        return prompt

    work_order = agenttask_work_order(payload)
    routing = agenttask_routing(payload)
    selector = agenttask_target_selector(payload)
    output_contract = agenttask_contract(payload, "output_contract")
    objective = agenttask_objective(payload) or policy_relevant_subagent_prompt_text(prompt)
    selected_agent = str(
        routing.get("selected_agent")
        or selector.get("agent_id")
        or selector.get("target")
        or selector.get("name")
        or payload.get("target")
        or ""
    ).strip()
    mode = str(routing.get("mode") or "").strip()

    lines = ["╭─ 子 Agent 工作单"]
    if selected_agent:
        lines.append(f"│ 发送给：{selected_agent}")
    if mode:
        lines.append(f"│ 调度模式：{mode}")

    def add_text_section(title: str, value: Any) -> None:
        text = clean_text(str(value or "")).strip()
        if not text:
            return
        lines.extend(["│", f"│ {title}"])
        for item in text.splitlines():
            lines.append(f"│ {item}" if item else "│")

    def add_list_section(title: str, values: Any) -> None:
        if not isinstance(values, list):
            return
        items = [clean_text(str(item or "")).strip() for item in values]
        items = [item for item in items if item]
        if not items:
            return
        lines.extend(["│", f"│ {title}"])
        for item in items:
            lines.append(f"│ - {item}")

    add_text_section("目标", objective)
    add_text_section("背景", work_order.get("background"))
    add_list_section("不要做", work_order.get("non_goals"))
    add_list_section("完成标准", work_order.get("success_criteria"))
    add_text_section("停止条件", work_order.get("stop_condition"))
    required = output_contract.get("required_sections")
    add_list_section("需要返回的内容", required)
    output_format = str(output_contract.get("format") or "").strip()
    if output_format:
        add_text_section("输出格式", output_format)

    lines.extend(["│", "│ 内部协议与工具权限已隐藏，执行侧仍保留完整 agenttask.v2。", "╰─"])
    return "\n".join(lines)


def apply_task_control(state: State, action: str, target: str, value: str, control: dict[str, Any], source: str = "agent") -> Optional[str]:
    action = (action or "").strip().lower().replace("-", "_")
    if action in {"task_plan", "plan", "plan_create"}:
        title = str(control.get("title") or control.get("name") or value or "任务计划").strip()
        steps = normalize_plan_steps(control.get("steps") or control.get("tasks") or control.get("items") or [])
        plan_id, step_ids = create_task_plan(state, title, steps, source=source)
        step_count = len({task_id for key, task_id in step_ids.items() if key.isdigit()})
        return f"已创建任务计划：{title} ({plan_id})，{step_count} 个步骤"
    if action in {"task_update", "task_done", "task_start", "task_fail", "task_cancel"}:
        task_id = resolve_plan_step_id(state, target) or target
        if not task_id:
            step = control.get("step")
            task_id = resolve_plan_step_id(state, step)
        if not task_id:
            return "缺少 task/step target。"
        status = str(control.get("status") or "").strip().lower()
        if action == "task_done":
            status = "completed"
        elif action == "task_start":
            status = "working"
        elif action == "task_fail":
            status = "failed"
        elif action == "task_cancel":
            status = "cancelled"
        if not status:
            status = "working"
        summary = str(control.get("summary") or control.get("message") or value or "").strip()
        append_task_update(task_id, status=status, summary=summary)
        if status == "completed":
            maybe_complete_plan_after_step(task_id)
        return f"已更新 task：{task_id} -> {status}"
    return None


def apply_dashboard_control(state: State, action: str, target: str, value: str, control: dict[str, Any], source: str = "agent") -> Optional[str]:
    del value
    action = (action or "").strip().lower().replace("-", "_")
    if action != "dashboard_update":
        return None
    target = str(target or control.get("target") or control.get("agent_id") or control.get("agent") or "").strip()
    if not target or target in {"current", "now", "selected"}:
        home_sub = selected_home_subagent(state)
        chat_sub = selected_subagent(state)
        target = home_sub.agent_id if home_sub is not None else (chat_sub.agent_id if chat_sub is not None else "main")
    if target.lower() in {"main", "orchestrator", "orchestrator.main", "主", "主控", "主agent", "主代理"}:
        state.main_dashboard = normalize_dashboard_spec_payload(control, source=source, target="orchestrator.main")
        mark_dirty(state)
        return "已更新主 agent 主页声明。"
    sub = resolve_subagent(state, target)
    if sub is None:
        return f"找不到子 agent: {target}"
    if not sub.persistent:
        return "临时子 agent 不持久化主页声明。"
    sub.dashboard = normalize_dashboard_spec_payload(control, source=source, target=sub.agent_id)
    sub.updated_at = time.time()
    save_subagent_meta(sub, state)
    append_subagent_event(sub, "dashboard.update", "dashboard.v1 updated", state=state)
    mark_dirty(state)
    return f"已更新代理主页声明：{sub.name}"


def apply_tui_controls_from_text(state: State, text: str, source: str = "agent", default_target: str = "current") -> list[str]:
    agent_source = "agent" in source
    controls = extract_tui_controls(text)
    agent_control_results: list[str] = []
    subagent_control_aliases: dict[str, str] = {}

    def record_control_result(action: str, target: str, result: str) -> None:
        message = f"Agent 控制: {result}"
        if agent_source:
            state.last_error = message
            agent_control_results.append(format_agent_control_result(action, target, result))
            mark_dirty(state)
        else:
            add_system(state, message)

    if not controls:
        for error in tui_control_parse_errors(text):
            record_control_result("parse_error", "", f"控制块解析失败：{error}")
        if agent_source and agent_control_results:
            add_system(
                state,
                "Agent 控制结果：\n" + "\n".join(agent_control_results),
                persist=True,
                kind="agent_control_result",
            )
        return agent_control_results

    for control in controls:
        action = str(control.get("action") or control.get("op") or "").strip().lower()
        target = str(control.get("target") or default_target or "current").strip()
        display_target = target
        value = str(control.get("value") or control.get("category") or control.get("name") or "").strip()
        expected_title = str(control.get("expected_title") or control.get("expect_title") or control.get("title") or "").strip()
        if not action:
            continue
        normalized_action = action.replace("-", "_")
        if (
            (normalized_action.startswith("subagent_") or normalized_action.startswith("agent_"))
            and normalized_action not in {"subagent_create", "agent_create", "create_subagent", "new_subagent"}
        ):
            target = resolve_subagent_control_alias(subagent_control_aliases, target)
        dashboard_result = apply_dashboard_control(state, action, target, value, control, source=source)
        if dashboard_result is not None:
            record_control_result(action, display_target, dashboard_result)
            continue
        schedule_result = apply_schedule_control(state, action, target, value, control, source=source)
        if schedule_result is not None:
            record_control_result(action, display_target, schedule_result)
            continue
        task_result = apply_task_control(state, action, target, value, control, source=source)
        if task_result is not None:
            record_control_result(action, display_target, task_result)
            continue
        subagent_result = apply_subagent_control(
            state,
            action,
            target,
            value,
            control,
            source=source,
            control_aliases=subagent_control_aliases,
        )
        if subagent_result is not None:
            record_control_result(action, display_target, subagent_result)
            continue
        if action in {"rename", "set_name", "name"}:
            path, error = resolve_session_target(state, target, allow_view_index=not agent_source or bool(expected_title), expected_title=expected_title)
            result = error if error else rename_session_path(state, path or "", value, source=source)
        else:
            if agent_source and action in {"archive", "delete", "remove"}:
                path, error = resolve_session_target(state, target, allow_view_index=False, expected_title=expected_title)
                if not error and path and is_current_session_path(state, path):
                    record_control_result(action, target, "已拒绝对当前打开会话执行归档/删除。")
                    continue
            result = apply_session_operation(
                state,
                action,
                target,
                value,
                source=source,
                allow_view_index=not agent_source or bool(expected_title),
                expected_title=expected_title,
            )
        record_control_result(action, target, result)

    if agent_source and agent_control_results:
        add_system(
            state,
            "Agent 控制结果：\n" + "\n".join(agent_control_results),
            persist=True,
            kind="agent_control_result",
        )
    return agent_control_results


def apply_secret_subagent_controls_from_text(state: State, text: str, source: str = "secret-agent") -> int:
    applied = 0
    alias_map: dict[str, str] = {}
    for control in extract_tui_controls(text, allow_json_fences=True):
        action = str(control.get("action") or control.get("op") or "").strip().lower()
        normalized_action = action.replace("-", "_")
        if not (normalized_action.startswith("subagent_") or normalized_action.startswith("agent_") or normalized_action in {"create_subagent", "new_subagent"}):
            continue
        target = str(control.get("target") or "current").strip()
        value = str(control.get("value") or control.get("category") or control.get("name") or "").strip()
        result = apply_subagent_control(state, action, target, value, control, source=source, control_aliases=alias_map)
        if result:
            add_system(state, f"Secret agent 控制: {result}")
            applied += 1
    return applied


def parse_category_command_args(state: State, args: str) -> tuple[str, str, str]:
    args = (args or "").strip()
    if not args:
        return "", "", "Usage: /category [n|current] <name>；用 - 清除分类。"
    parts = args.split(maxsplit=1)
    if len(parts) == 2:
        path, error = resolve_session_target(state, parts[0])
        if path and not error:
            return parts[0], parts[1], ""
    return "current", args, ""


AGENT_SUBCOMMANDS = command_helpers.AGENT_SUBCOMMANDS
AGENT_SUBCOMMANDS_REQUIRING_AGENT = command_helpers.AGENT_SUBCOMMANDS_REQUIRING_AGENT
AGENT_SUBCOMMANDS_SEND_AFTER_AGENT = command_helpers.AGENT_SUBCOMMANDS_SEND_AFTER_AGENT
WORKSPACE_SUBCOMMANDS = command_helpers.WORKSPACE_SUBCOMMANDS
AgentCommandCompletionDecision = command_helpers.AgentCommandCompletionDecision
completion_insert_text = command_helpers.completion_insert_text
top_level_command_matches = command_helpers.top_level_command_matches
category_command_completion_rows = command_helpers.category_command_completion_rows
approval_command_completion_rows = command_helpers.approval_command_completion_rows
agent_command_completion_decision = command_helpers.agent_command_completion_decision
subagent_settings_target_from_command = command_helpers.subagent_settings_target_from_command


def subagent_completion_rows(state: Optional[State], prefix: str, subcmd: str) -> list[tuple[str, str, str, bool]]:
    if state is None:
        return []
    rows: list[tuple[str, str, str, bool]] = []
    for sub in sorted(state.subagents.values(), key=lambda item: item.updated_at, reverse=True):
        token = sub.agent_id
        if prefix and not (token.lower().startswith(prefix.lower()) or sub.name.lower().startswith(prefix.lower())):
            continue
        sendable = subcmd in AGENT_SUBCOMMANDS_SEND_AFTER_AGENT
        args = "" if sendable else {
            "ask": "<prompt>",
            "run": "<prompt>",
            "input": "<prompt>",
            "answer": "<text>",
            "reply": "<text>",
            "remember": "<text>",
            "rename": "<new-name>",
            "role": "<role>",
        }.get(subcmd, "[text]")
        rows.append((f"/agent {subcmd} {token}", args, f"{sub.name} · {sub.status}", sendable))
    return rows


def agent_command_matches(text: str, state: Optional[State]) -> list[tuple[str, str, str, bool]]:
    decision = agent_command_completion_decision(text)
    if decision.kind == "rows":
        return list(decision.rows)
    if decision.kind == "role":
        return [
            (decision.role_base + role, "", str(template.get("description") or ""), True)
            for role, template in ROLE_TEMPLATES.items()
            if not decision.role_prefix or role.startswith(decision.role_prefix)
        ]
    if decision.kind == "subagent":
        return subagent_completion_rows(state, decision.agent_prefix, decision.subcmd)
    return []


def category_command_matches(text: str, state: Optional[State]) -> list[tuple[str, str, str, bool]]:
    if state is None:
        return []
    counts: dict[str, int] = {}
    labels: dict[str, str] = {}
    for path, _mtime, _first, _rounds in state.history:
        label = session_category_label(session_meta_for(state, path))
        key = category_key(label)
        labels[key] = label
        counts[key] = counts.get(key, 0) + 1
    category_counts = [
        (labels[key], counts.get(key, 0))
        for key in sorted(labels, key=lambda item: category_sort_key(labels[item]))
    ]
    return category_command_completion_rows(text, category_counts)


archived_command_matches = command_helpers.archived_command_matches
workspace_command_matches = command_helpers.workspace_command_matches


def approval_command_matches(text: str, state: Optional[State] = None) -> list[tuple[str, str, str, bool]]:
    if not re.match(r"^/(approve|reject)\s+", text or "", re.I):
        return []
    approval_candidates = [
        (
            str(row.get("approval_id") or ""),
            truncate_cells(str(row.get("summary") or ""), 70),
        )
        for row in pending_approvals(state)
    ]
    return approval_command_completion_rows(text, approval_candidates)


def command_matches(text: str, state: Optional[State] = None) -> list[tuple[str, str, str, bool]]:
    raw = text or ""
    stripped = raw.strip()
    if not stripped.startswith("/"):
        return []
    if re.match(r"^/agent(?:\s|$)", raw):
        return agent_command_matches(raw, state)
    if re.match(r"^/workspaces?(?:\s|$)", raw, re.I):
        return workspace_command_matches(raw)
    if re.match(r"^/(?:filter|collapse|expand)\s", raw, re.I):
        return category_command_matches(raw, state)
    if re.match(r"^/archived\s", raw, re.I):
        return archived_command_matches(raw)
    if re.match(r"^/(?:approve|reject)\s", raw, re.I):
        return approval_command_matches(raw, state)
    return top_level_command_matches(stripped, COMMANDS)


def clamp_command_index(state: State, matches: list[tuple[str, str, str, bool]]) -> None:
    if not matches:
        state.command_index = 0
    else:
        state.command_index = max(0, min(state.command_index, len(matches) - 1))


def selected_subagent(state: State) -> Optional[SubAgentRuntime]:
    return state.subagents.get(str(state.selected_session or ""))


def selected_home_subagent(state: State) -> Optional[SubAgentRuntime]:
    agent_id = home_subagent_id_from_key(state.selected_session)
    if not agent_id:
        return None
    return state.subagents.get(agent_id)


def active_subagent_view(state: State) -> Optional[SubAgentRuntime]:
    return selected_subagent(state) or selected_home_subagent(state)


def model_manager_subagent_targets(state: State) -> list[SubAgentRuntime]:
    active = active_subagent_view(state)
    targets: list[SubAgentRuntime] = []
    if active is not None and active.status != "deleted":
        targets.append(active)
    active_id = active.agent_id if active is not None else ""
    for sub in state.subagents.values():
        if sub.agent_id == active_id or sub.status == "deleted":
            continue
        targets.append(sub)
    return targets


def set_selected_interface(state: State, key: Any, *, follow_bottom: bool = True) -> None:
    state.selected_session = key
    if follow_bottom:
        state.follow_bottom = True
    state.scroll = 0
    mark_dirty(state)


def show_main_home(state: State, *, message: str = "") -> None:
    set_selected_interface(state, MAIN_HOME_SESSION_KEY, follow_bottom=False)
    if message:
        state.last_error = message


def show_scheduled_reports_home(state: State, *, message: str = "") -> None:
    set_selected_interface(state, SCHEDULED_REPORTS_SESSION_KEY, follow_bottom=False)
    if message:
        state.last_error = message


def show_subagent_home(state: State, sub: SubAgentRuntime, *, message: str = "") -> None:
    if not sub.persistent:
        set_selected_interface(state, sub.agent_id)
        state.last_error = message or f"{sub.name} 是临时会话代理，默认显示聊天。"
        return
    set_selected_interface(state, subagent_home_session_key(sub.agent_id), follow_bottom=False)
    if message:
        state.last_error = message


def show_home_for_current_scope(state: State, target: str = "") -> str:
    target = str(target or "").strip()
    if target:
        if target.lower() in {"main", "orchestrator", "orchestrator.main", "主", "主控", "主agent", "主代理"}:
            show_main_home(state)
            return "已打开主 agent 主页。"
        if target.lower() in {"reports", "report", "scheduled_reports", "scheduled-reports", "schedule_reports", "定时汇报", "汇报"}:
            show_scheduled_reports_home(state)
            return "已打开定时汇报。"
        sub = resolve_subagent(state, target)
        if sub is None:
            return f"找不到子 agent: {target}"
        if not sub.persistent:
            return f"{sub.name} 是临时会话代理，没有持久主页。"
        show_subagent_home(state, sub)
        return f"已打开代理主页：{sub.name}"
    home_sub = selected_home_subagent(state)
    if home_sub is not None:
        show_subagent_home(state, home_sub)
        return f"已打开代理主页：{home_sub.name}"
    chat_sub = selected_subagent(state)
    if chat_sub is not None:
        if not chat_sub.persistent:
            return f"{chat_sub.name} 是临时会话代理，没有持久主页。"
        show_subagent_home(state, chat_sub)
        return f"已打开代理主页：{chat_sub.name}"
    show_main_home(state)
    return "已打开主 agent 主页。"


def switch_home_to_chat(state: State) -> str:
    home_sub = selected_home_subagent(state)
    if home_sub is not None:
        switch_to_subagent_chat_session(state, home_sub.agent_id, "")
        return f"已切到代理聊天：{home_sub.name}"
    if is_scheduled_reports_session_key(state.selected_session):
        return "定时汇报是只读治理页面；用 /home 回主主页，或点击右侧/左侧会话继续聊天。"
    if is_main_home_session_key(state.selected_session):
        set_selected_interface(state, "main")
        return "已切到主 agent 聊天。"
    return "当前已经是聊天或历史界面。"


def mark_subagent_messages_changed(state: State, sub: SubAgentRuntime, *, follow_bottom: bool = True) -> None:
    if selected_subagent(state) is sub:
        if follow_bottom:
            state.follow_bottom = True
        mark_messages_changed(state)
    else:
        mark_dirty(state)


def queue_subagent_chat_input(state: State, sub: SubAgentRuntime, text: str, *, interrupt_requested: bool = False) -> str:
    queued = (text or "").strip()
    if not queued:
        return ""
    sub.chat_queue.append(queued)
    if interrupt_requested:
        sub.chat_queue_interrupt_requested = True
    sub.updated_at = time.time()
    append_subagent_visible_system_notice(
        state,
        sub,
        f"已排队聊天输入：{truncate_cells(queued, 160)}\n当前子 agent 正在回复，队列会在当前输出结束后自动发送。",
        source="subagent_chat_queued",
    )
    mark_dirty(state)
    return f"{sub.name} 正在回复，已排队 {len(sub.chat_queue)} 条聊天输入。"


def maybe_start_next_subagent_chat(state: State, sub: SubAgentRuntime) -> Optional[str]:
    if sub.status in {"running", "aborting"} or sub.active_task_id is not None:
        return None
    if not sub.chat_queue:
        return None
    queued = list(sub.chat_queue)
    interrupt_requested = sub.chat_queue_interrupt_requested
    sub.chat_queue.clear()
    sub.chat_queue_interrupt_requested = False
    prompt = "\n\n".join(text for text in queued if text.strip()).strip()
    if not prompt:
        mark_dirty(state)
        return None
    return start_subagent_chat(
        state,
        sub,
        prompt,
        source="subagent_chat:queued_after_interrupt" if interrupt_requested else "subagent_chat:queued",
    )


def request_subagent_interrupt(state: State, sub: SubAgentRuntime, prefix: str = "Ctrl+C") -> None:
    if sub.status in {"running", "aborting"} and state.input_text.strip() and not secret_password_entry_active(state):
        draft = state.input_text
        set_input_text(state, "")
        queue_subagent_chat_input(state, sub, draft, interrupt_requested=True)
    if sub.status in {"running", "aborting"}:
        if sub.agent is not None:
            try:
                sub.agent.abort()
            except Exception:
                pass
        sub.status = "aborting"
        sub.updated_at = time.time()
        if sub.chat_queue:
            sub.chat_queue_interrupt_requested = True
            state.last_error = f"{prefix}: 已请求中止子 agent；排队输入会在当前输出收尾后发送。"
        else:
            state.last_error = f"{prefix}: 已请求中止子 agent；退出 TUI 请按 Ctrl+Q。"
        mark_dirty(state)
        return
    state.last_error = f"{prefix} 只用于中止当前可见任务；退出 TUI 请按 Ctrl+Q。"
    mark_dirty(state)


def request_visible_interrupt(state: State, prefix: str = "Ctrl+C") -> None:
    sub = active_subagent_view(state)
    if sub is not None:
        request_subagent_interrupt(state, sub, prefix=prefix)
    else:
        request_main_interrupt(state, prefix=prefix)


