def agent_task_rows(agent_id: str, *, include_terminal: bool = True, limit: int = 8) -> list[dict[str, Any]]:
    rows = [
        row for row in latest_task_records().values()
        if str(row.get("assigned_agent") or "") == agent_id
    ]
    if not include_terminal:
        rows = [row for row in rows if not terminal_task_status(str(row.get("status") or ""))]
    rows.sort(key=row_timestamp, reverse=True)
    return rows[:limit]


def schedule_row_targets_agent(row: dict[str, Any], agent_id: str) -> bool:
    if str(row.get("target") or "") == agent_id:
        return True
    execution = row.get("execution") if isinstance(row.get("execution"), dict) else {}
    if schedule_execution_target(execution) == agent_id:
        return True
    control = schedule_agenttask_control(row)
    routing = control.get("routing") if isinstance(control.get("routing"), dict) else {}
    selector = routing.get("target_selector") if isinstance(routing.get("target_selector"), dict) else {}
    return str(routing.get("selected_agent") or selector.get("agent_id") or selector.get("target") or "") == agent_id


def agent_schedule_rows(agent_id: str, limit: int = 8) -> list[dict[str, Any]]:
    rows = [
        row for row in latest_schedule_records().values()
        if schedule_row_targets_agent(row, agent_id)
    ]
    rows.sort(key=lambda item: str(item.get("updated_at") or item.get("created_at") or ""), reverse=True)
    return rows[:limit]


def artifact_rows_by_source_task() -> dict[str, dict[str, Any]]:
    by_task: dict[str, dict[str, Any]] = {}
    for row in artifact_index_latest().values():
        task_id = str(row.get("source_task_id") or "").strip()
        if not task_id:
            continue
        uri = str(row.get("uri") or row.get("path") or "").strip()
        artifact_type = str(row.get("type") or "").strip()
        if artifact_type != "subagent-results" and "/subagent-results/" not in uri:
            continue
        current = by_task.get(task_id)
        row_ts = row_timestamp(row) or float(row.get("mtime") or 0.0)
        current_ts = (row_timestamp(current) or float(current.get("mtime") or 0.0)) if current else -1.0
        if current is None or row_ts >= current_ts:
            by_task[task_id] = row
    return by_task


def scheduled_report_visible_text(text: str) -> str:
    cleaned = clean_text(strip_subagent_memory_controls(strip_tui_controls(text or ""))).strip()
    if not cleaned:
        return ""
    parts = split_top_level_turn_markers(cleaned)
    if len(parts) >= 3:
        turns: list[tuple[str, str]] = []
        for idx in range(1, len(parts), 2):
            marker = parts[idx]
            body = parts[idx + 1] if idx + 1 < len(parts) else ""
            turns.append((marker, body))
        visible = preferred_group_visible_reply(turns).strip()
    else:
        visible = visible_reply_text(cleaned, hide_detail_fences=process_has_tool_noise(cleaned)).strip()
    visible = clean_text(strip_inline_markdown(visible)).strip()
    visible = sanitize_scheduled_report_visible_text(visible)
    noise_markers = ("LLM Running", "<summary>", "<thinking>", "<think>", "过程组", "过程 Turn")
    if not visible or any(marker in visible for marker in noise_markers):
        return ""
    return visible


def sanitize_scheduled_report_visible_text(text: str) -> str:
    cleaned = text or ""
    cleaned = re.sub(r"artifact://\S+", "[artifact]", cleaned)
    cleaned = re.sub(r"\bappr_[A-Za-z0-9_:-]+\b", "[approval]", cleaned)
    cleaned = re.sub(r"\btask_[A-Za-z0-9_:-]+\b", "[task]", cleaned)
    lines: list[str] = []
    for raw_line in cleaned.splitlines():
        if "APPROVAL_REQUIRED" in raw_line:
            continue
        lines.append(raw_line.rstrip())
    return clean_text("\n".join(lines)).strip()


def scheduled_report_excerpt(text: str, limit: int = 260) -> str:
    cleaned = scheduled_report_visible_text(text)
    if not cleaned:
        return ""
    lines = []
    for raw_line in cleaned.splitlines():
        line = re.sub(r"^\s*#{1,6}\s+", "", raw_line).strip(" -\t")
        line = re.sub(r"(?i)^(summary|摘要|总结)\s*[:：]\s*", "", line).strip()
        if re.fullmatch(r"(?i)(summary|摘要|总结|运行结果|report|报告)", line):
            continue
        if line:
            lines.append(line)
    excerpt = " / ".join(lines[:3]).strip()
    return truncate_cells(excerpt or cleaned.replace("\n", " "), limit)


def scheduled_report_body(text: str, limit: int = 12000) -> str:
    cleaned = scheduled_report_visible_text(text)
    if not cleaned:
        return ""
    return truncate_cells(cleaned, limit).strip()


def task_artifact_ref_for_scheduled_report(task_row: dict[str, Any], artifacts_by_task: dict[str, dict[str, Any]]) -> str:
    artifact_ref = subagent_result_artifact_ref(task_row.get("artifact_refs"))
    if artifact_ref:
        return artifact_ref
    task_id = str(task_row.get("task_id") or "").strip()
    artifact_row = artifacts_by_task.get(task_id) if task_id else None
    if artifact_row:
        return str(artifact_row.get("uri") or artifact_row.get("path") or "").strip()
    return ""


def scheduled_report_agent_name(state: Optional[State], agent_id: str, fallback: str = "") -> str:
    agent_id = str(agent_id or "").strip()
    if state is not None and agent_id in state.subagents:
        return state.subagents[agent_id].name
    meta = load_subagent_meta(agent_id) if agent_id else {}
    return str(meta.get("name") or fallback or agent_id or "子 agent")


def scheduled_report_rows(state: Optional[State] = None, *, agent_id: str = "", limit: int = 12) -> list[dict[str, Any]]:
    target_agent = str(agent_id or "").strip()
    tasks = latest_task_records()
    schedules = latest_schedule_records()
    artifacts_by_task = artifact_rows_by_source_task()
    rows: list[dict[str, Any]] = []
    seen_tasks: set[str] = set()
    for run in reversed(latest_schedule_run_records(limit=2000)):
        task_id = str(run.get("task_id") or "").strip()
        if not task_id or task_id in seen_tasks:
            continue
        task = tasks.get(task_id)
        if not task:
            continue
        assigned_agent = str(task.get("assigned_agent") or run.get("target") or "").strip()
        if target_agent and assigned_agent != target_agent:
            continue
        if not assigned_agent:
            continue
        kind = str(task.get("kind") or "").strip()
        if kind not in {"subagent_task", "subagent"} and not assigned_agent.startswith(("agent-", "tmp-agent-", "tmp-")):
            continue
        status = str(task.get("status") or run.get("status") or "-").strip()
        if status.lower() != "completed":
            continue
        schedule_id = str(run.get("schedule_id") or "").strip()
        schedule = schedules.get(schedule_id, {})
        schedule_name = str(run.get("schedule_name") or schedule.get("name") or schedule_id or "定时任务")
        artifact_ref = task_artifact_ref_for_scheduled_report(task, artifacts_by_task)
        artifact_body = subagent_result_body_from_artifact(artifact_ref) if artifact_ref else ""
        body = (
            scheduled_report_body(artifact_body)
            or scheduled_report_body(str(task.get("summary") or ""), limit=4000)
        )
        if not body:
            continue
        summary = scheduled_report_excerpt(body) or truncate_cells(body.replace("\n", " "), 260)
        timestamp = str(task.get("timestamp") or run.get("finished_at") or run.get("timestamp") or "").strip()
        row = {
            "schedule_id": schedule_id,
            "schedule_name": schedule_name,
            "trigger": str(run.get("trigger") or schedule_record_trigger(schedule) or "").strip(),
            "task_id": task_id,
            "agent_id": assigned_agent,
            "agent_name": scheduled_report_agent_name(state, assigned_agent, str(run.get("target_name") or "")),
            "status": status or "-",
            "timestamp": timestamp,
            "summary": summary,
            "body": body,
            "artifact_ref": artifact_ref,
        }
        rows.append(row)
        seen_tasks.add(task_id)
    rows.sort(key=lambda item: parse_iso_timestamp(str(item.get("timestamp") or "")), reverse=True)
    return rows[:limit]


def scheduled_report_body_lines(
    body: str,
    *,
    width: int,
    limit: int,
    max_lines: int,
    payload: dict[str, str],
) -> list[RenderLine]:
    text = truncate_cells(str(body or "").strip(), limit).strip()
    if not text:
        return []
    rendered = markdown_blocks(text, max(24, width - 4))
    lines: list[RenderLine] = []
    blank_seen = False
    truncated = False
    for item in rendered:
        if len(lines) >= max_lines:
            truncated = True
            break
        text_line = item.text.rstrip()
        if not text_line:
            if blank_seen:
                continue
            blank_seen = True
            lines.append(RenderLine("", item.attr, kind="scheduled_report", payload=dict(payload)))
            continue
        blank_seen = False
        lines.append(RenderLine(f"  {text_line}", item.attr, kind="scheduled_report", payload=dict(payload)))
    if truncated:
        lines.append(RenderLine("  ...（汇报内容过长，更多见任务详情）", cp(9), kind="scheduled_report", payload=dict(payload)))
    return lines


def scheduled_report_lines(
    rows: list[dict[str, Any]],
    *,
    include_agent: bool = True,
    width: int = 100,
    body_limit: int = 12000,
    max_body_lines: int = 120,
) -> list[RenderLine | str]:
    lines: list[RenderLine | str] = []
    for row in rows:
        parts = [str(row.get("schedule_name") or row.get("schedule_id") or "定时任务")]
        if include_agent:
            parts.append(str(row.get("agent_name") or row.get("agent_id") or "子 agent"))
        parts.append(str(row.get("status") or "-"))
        timestamp = str(row.get("timestamp") or "").strip()
        if timestamp:
            parts.append(timestamp)
        payload = {
            "task_id": str(row.get("task_id") or ""),
            "schedule_id": str(row.get("schedule_id") or ""),
            "agent_id": str(row.get("agent_id") or ""),
            "artifact_ref": str(row.get("artifact_ref") or ""),
        }
        lines.append(RenderLine(
            f"- {' · '.join(parts)}",
            cp(2),
            kind="scheduled_report",
            payload=payload,
        ))
        body = str(row.get("body") or row.get("summary") or "").strip()
        if body:
            lines.extend(scheduled_report_body_lines(
                body,
                width=width,
                limit=body_limit,
                max_lines=max_body_lines,
                payload=payload,
            ))
    return lines


def agent_artifact_rows(agent_id: str, limit: int = 8) -> list[dict[str, Any]]:
    task_ids = {str(row.get("task_id") or "") for row in agent_task_rows(agent_id, limit=40)}
    rows = [
        row for row in artifact_index_latest().values()
        if str(row.get("source_task_id") or "") in task_ids
    ]
    rows.sort(key=lambda row: row_timestamp(row) or float(row.get("mtime") or 0.0), reverse=True)
    return rows[:limit]


def agent_approval_rows(state: Optional[State], agent_id: str, limit: int = 8) -> list[dict[str, Any]]:
    task_ids = {str(row.get("task_id") or "") for row in agent_task_rows(agent_id, limit=40)}
    rows = []
    for row in pending_approvals(state):
        payload = row.get("payload") if isinstance(row.get("payload"), dict) else {}
        target = str(row.get("target") or payload.get("subagent_id") or payload.get("target_subagent") or "")
        task_id = str(payload.get("task_id") or "")
        if target == agent_id or task_id in task_ids:
            rows.append(row)
    rows.sort(key=row_timestamp, reverse=True)
    return rows[:limit]


def main_recent_session_rows(state: State, limit: int = 8) -> list[RenderLine]:
    load_history(state, force=True)
    entries = list(enumerate(state.history, 1))
    recent = recent_history_items(entries, set(), limit=limit)
    rows: list[RenderLine] = []
    for _idx, (path, mtime, preview, rounds) in recent:
        title = compact_title(history_name(state, path) or preview or os.path.basename(path), 80)
        meta = session_meta_for(state, path)
        category = session_category_label(meta)
        parts = [f"{int(rounds or 0)} 轮", rel_age(float(mtime or 0.0))]
        if category and category != "未分类":
            parts.insert(0, category)
        if is_current_session_path(state, path):
            parts.append("当前会话")
        parts.append("点击打开")
        rows.append(RenderLine(
            f"- {title or '历史会话'} · {' · '.join(parts)}",
            cp(2),
            kind="home_session_link",
            payload={"action": "open_session", "session_type": "history", "path": path},
        ))
    return rows


def subagent_recent_session_rows(state: State, sub: SubAgentRuntime, limit: int = 8) -> list[RenderLine]:
    entries = subagent_chat_session_entries(state, sub)
    current_known = {str(entry.get("session_id") or "") for entry in entries}
    if sub.chat_session_id and sub.chat_session_id not in current_known and sub.messages:
        entries.insert(0, {
            "agent_id": sub.agent_id,
            "session_id": sub.chat_session_id,
            "title": subagent_chat_title_for_messages(sub),
            "updated_at": now_iso(),
            "message_count": len(sub.messages),
            "current": True,
        })
    rows: list[RenderLine] = []
    for entry in entries[:limit]:
        session_id = str(entry.get("session_id") or "")
        if not session_id:
            continue
        title = compact_title(str(entry.get("title") or session_id or "子 agent 会话"), 80)
        updated = parse_iso_timestamp(str(entry.get("updated_at") or ""))
        parts = [f"{int(entry.get('message_count') or 0)} 条消息"]
        if updated:
            parts.append(rel_age(updated))
        if session_id == sub.chat_session_id or entry.get("current"):
            parts.append("当前会话")
        if entry.get("error"):
            parts.append("读取异常")
        else:
            parts.append("点击打开")
        rows.append(RenderLine(
            f"- {title or '子 agent 会话'} · {' · '.join(parts)}",
            cp(2),
            kind="home_session_link",
            payload={
                "action": "open_session",
                "session_type": "subagent",
                "agent_id": sub.agent_id,
                "session_id": session_id,
            },
        ))
    return rows


def append_home_line(
    lines: list[RenderLine],
    text: str = "",
    attr: int = 0,
    *,
    width: int = 80,
    kind: str = "",
    payload: Optional[dict[str, Any]] = None,
) -> None:
    for part in wrap_cells(text, width):
        lines.append(RenderLine(part, attr, kind=kind, payload=dict(payload or {})))


def append_home_section(lines: list[RenderLine], title: str, body: list[str | RenderLine], width: int) -> None:
    lines.append(RenderLine(""))
    lines.append(RenderLine(f"## {title}", cp(7) | curses.A_BOLD))
    if not body:
        lines.append(RenderLine("  - 暂无", cp(9)))
        return
    for raw in body:
        if isinstance(raw, RenderLine):
            append_home_line(lines, raw.text, raw.attr, width=width, kind=raw.kind, payload=raw.payload)
        else:
            append_home_line(lines, raw, cp(2), width=width)


def append_status_card(
    lines: list[RenderLine],
    *,
    title: str,
    summary: str,
    metrics: list[tuple[str, str]],
    details: list[tuple[str, str]],
    width: int,
) -> None:
    card_width = max(32, min(width, 110))
    inner_width = max(24, card_width - 4)
    lines.append(RenderLine("固定状态卡", cp(1) | curses.A_BOLD))
    lines.append(RenderLine(status_card_header_line(title, card_width), cp(10) | curses.A_BOLD))
    for wrapped in wrap_cells(summary, inner_width):
        lines.append(RenderLine(status_card_content_line(wrapped, card_width), cp(2)))
    lines.append(RenderLine(status_card_divider_line(status_card_metric_header(metrics), card_width), cp(10)))
    for row in status_card_metric_rows(metrics, inner_width):
        lines.append(RenderLine(status_card_content_line(row, card_width), cp(7) | curses.A_BOLD))
    lines.append(RenderLine(status_card_divider_line("运行详情", card_width), cp(10)))
    for row in status_card_detail_rows(details, inner_width):
        lines.append(RenderLine(status_card_content_line(row, card_width), cp(2)))
    lines.append(RenderLine(status_card_footer_line(card_width), cp(10)))


def append_home_action_panel(lines: list[RenderLine], title: str, actions: list[tuple[str, str]], width: int) -> None:
    card_width = max(32, min(width, 110))
    inner_width = max(24, card_width - 4)
    cleaned = [
        (str(label or "").strip(), str(value or "").strip())
        for label, value in actions
        if str(label or "").strip() or str(value or "").strip()
    ]
    if not cleaned:
        return
    label_width = min(12, max(4, max((cell_width(label) for label, _value in cleaned), default=4)))
    lines.append(RenderLine(""))
    lines.append(RenderLine(status_card_header_line(title, card_width), cp(10) | curses.A_BOLD))
    for label, value in cleaned:
        value_width = max(8, inner_width - label_width - 3)
        wrapped = wrap_cells(value or "-", value_width)
        for idx, part in enumerate(wrapped):
            prefix = pad_cells(label, label_width) + "   " if idx == 0 else " " * (label_width + 3)
            lines.append(RenderLine(status_card_content_line(prefix + part, card_width), cp(2)))
    lines.append(RenderLine(status_card_footer_line(card_width), cp(10)))


def main_home_section_body(
    state: State,
    section: dict[str, Any],
    *,
    task_rows: list[dict[str, Any]],
    open_tasks: list[dict[str, Any]],
    approvals: list[dict[str, Any]],
    schedule_registry: dict[str, Any],
    artifacts: list[dict[str, Any]],
) -> list[str | RenderLine]:
    section_type = str(section.get("type") or "")
    if section_type == "function":
        markdown = bounded_dashboard_text(section.get("markdown"), 1200)
        if markdown:
            return markdown.splitlines()[:30]
        return [
            "- 枢衡主 agent 是强 Orchestrator：负责接收用户意图、拆解任务、调度受限子 agent、维护共享账本并串联审批门禁。",
            "- 子 agent 主页、任务、定时任务、审批、trace、artifact 都从共享治理数据读取；主页本身不直接执行任务或审批。",
        ]
    if section_type == "status_narrative":
        return [dashboard_status_for_main(state, open_tasks=open_tasks, approvals=approvals, schedule_registry=schedule_registry)]
    if section_type == "todos":
        todos = dashboard_todos_for_main(state)
        if not todos:
            todos = [
                f"{task_display_title(row, state)} · {row.get('status') or '-'} · owner:{row.get('assigned_agent') or '-'}"
                for row in open_tasks[:8]
            ]
        return [f"- {item}" for item in todos]
    if section_type == "sessions":
        return main_recent_session_rows(state)
    if section_type == "schedules":
        jobs = list(schedule_registry.get("jobs") or [])
        jobs.sort(key=lambda row: str(row.get("updated_at") or row.get("created_at") or ""), reverse=True)
        return [
            f"- {row.get('name') or row.get('schedule_id')} · {row.get('status') or 'enabled'} · "
            f"{row.get('trigger') or row.get('cron') or row.get('interval') or row.get('at') or '-'}"
            for row in jobs[:8]
        ]
    if section_type == "tasks":
        return [
            f"- {task_display_title(row, state)} · {row.get('status') or '-'} · {row.get('timestamp') or ''}"
            for row in task_rows[:8]
        ]
    if section_type == "artifacts":
        artifacts.sort(key=lambda row: row_timestamp(row) or float(row.get("mtime") or 0.0), reverse=True)
        return [
            f"- {row.get('uri') or row.get('path') or row.get('artifact_id')} · {row.get('type') or '-'}"
            for row in artifacts[:8]
        ]
    if section_type == "approvals":
        return [
            f"- {row.get('approval_id') or '-'} · {row.get('type') or '-'} · {row.get('summary') or '-'}"
            for row in approvals[:8]
        ]
    if section_type == "memory":
        return [
            "- 主 agent 长期上下文由 Shuheng 记忆、历史会话摘要和共享治理账本提供。",
            "- 记忆写入仍需要候选与审批流程；主页只展示摘要，不直接写入长期记忆。",
        ]
    if section_type == "markdown":
        spec = dashboard_spec_for_main(state)
        markdown = bounded_dashboard_text(section.get("markdown") or spec.get("markdown"), 3000)
        return markdown.splitlines()[:80] if markdown else []
    return []


def main_home_lines_uncached(state: State, width: int) -> list[RenderLine]:
    task_rows = list(latest_task_records().values())
    task_rows.sort(key=row_timestamp, reverse=True)
    open_tasks = [row for row in task_rows if not terminal_task_status(str(row.get("status") or ""))]
    approvals = pending_approvals(state)
    schedule_registry = scheduled_task_registry(state)
    artifacts = list(artifact_index_latest().values())
    provider = "-"
    try:
        provider = str(state.agent.get_llm_name(model=True))
    except Exception:
        provider = agent_current_backend_name(state.agent) or "-"
    lines = [
        RenderLine("Shuheng 主 agent 主页", cp(7) | curses.A_BOLD),
    ]
    main_summary = dashboard_status_for_main(
        state,
        open_tasks=open_tasks,
        approvals=approvals,
        schedule_registry=schedule_registry,
    )
    append_status_card(
        lines,
        title="主控运行概览",
        summary=main_summary,
        metrics=[
            ("状态", state.status),
            ("活跃任务", str(len(open_tasks))),
            ("待审批", str(len(approvals))),
            ("定时任务", f"{schedule_registry.get('active_job_count', 0)}/{schedule_registry.get('job_count', 0)}"),
            ("Artifact", str(len(artifacts))),
            ("后台会话", str(len(state.background_sessions))),
        ],
        details=[
            ("当前会话", state.current_title or "main"),
            ("运行模型", provider),
            ("调度来源", "shared registry"),
            ("主页模式", "main orchestrator"),
        ],
        width=width,
    )
    for section in dashboard_sections_for_main(state):
        title = str(section.get("title") or section.get("type") or "section")
        body = main_home_section_body(
            state,
            section,
            task_rows=task_rows,
            open_tasks=open_tasks,
            approvals=approvals,
            schedule_registry=schedule_registry,
            artifacts=list(artifacts),
        )
        append_home_section(lines, title, body, width)
    append_home_action_panel(lines, "详情入口", [
        ("继续对话", "/chat"),
        ("治理面板", "/tasks  /schedules  /approvals  /artifacts"),
        ("代理主页", "点击右侧持久 agent"),
    ], width)
    return lines


def scheduled_reports_home_lines_uncached(state: State, width: int) -> list[RenderLine]:
    rows = scheduled_report_rows(state, limit=24)
    completed = sum(1 for row in rows if str(row.get("status") or "").lower() == "completed")
    active = sum(1 for row in rows if not terminal_task_status(str(row.get("status") or "")))
    agents = {str(row.get("agent_id") or "") for row in rows if str(row.get("agent_id") or "")}
    schedules = {str(row.get("schedule_id") or "") for row in rows if str(row.get("schedule_id") or "")}
    latest = rows[0] if rows else {}
    summary = (
        f"已汇总 {len(rows)} 条子 agent 定时任务回复；"
        f"{completed} 条已完成，{active} 条仍在处理中。"
        if rows else
        "还没有可展示的子 agent 定时回复；定时任务完成后会自动出现在这里。"
    )
    lines = [RenderLine("定时汇报", cp(7) | curses.A_BOLD)]
    append_status_card(
        lines,
        title="定时汇报总览",
        summary=summary,
        metrics=[
            ("汇报", str(len(rows))),
            ("已完成", str(completed)),
            ("处理中", str(active)),
            ("子代理", str(len(agents))),
            ("定时任务", str(len(schedules))),
            ("Artifact", str(sum(1 for row in rows if str(row.get("artifact_ref") or "")))),
        ],
        details=[
            ("最新汇报", str(latest.get("schedule_name") or "-")),
            ("来源", "schedule_runs + task ledger + artifacts"),
            ("页面模式", "scheduled reports"),
            ("入口", "左上角主页并行页面"),
        ],
        width=width,
    )
    append_home_section(
        lines,
        "最近定时汇报",
        scheduled_report_lines(rows, include_agent=True, width=width, body_limit=12000, max_body_lines=120),
        width,
    )
    append_home_action_panel(lines, "详情入口", [
        ("定时任务", "/schedules"),
        ("任务账本", "/tasks"),
        ("代理主页", "点击右侧持久 agent"),
    ], width)
    return lines


def subagent_home_section_body(state: State, sub: SubAgentRuntime, section: dict[str, Any], *, width: int = 100) -> list[str | RenderLine]:
    section_type = str(section.get("type") or "")
    if section_type == "function":
        profile = profile_summary_for_subagent(sub)
        role = normalized_subagent_role(sub.role)
        return profile.splitlines()[:20] if profile else [f"- 角色: {role}", f"- 写策略: {role_template(role).get('write_policy', 'none')}"]
    if section_type == "status_narrative":
        return [dashboard_status_for_subagent(sub)]
    if section_type == "todos":
        todos = dashboard_todos_for_subagent(sub)
        if not todos:
            todos = [
                f"{task_display_title(row, state)} · {row.get('status') or '-'}"
                for row in agent_task_rows(sub.agent_id, include_terminal=False, limit=8)
            ]
        return [f"- {item}" for item in todos]
    if section_type == "sessions":
        return subagent_recent_session_rows(state, sub)
    if section_type == "schedules":
        rows = []
        for row in agent_schedule_rows(sub.agent_id):
            rows.append(
                f"- {row.get('name') or row.get('schedule_id')} · {row.get('status') or 'enabled'} · "
                f"{row.get('trigger') or row.get('cron') or row.get('interval') or row.get('at') or '-'}"
            )
        return rows
    if section_type == "scheduled_reports":
        return scheduled_report_lines(
            scheduled_report_rows(state, agent_id=sub.agent_id, limit=8),
            include_agent=False,
            width=width,
            body_limit=10000,
            max_body_lines=100,
        )
    if section_type == "tasks":
        return [
            f"- {task_display_title(row, state)} · {row.get('status') or '-'} · {row.get('timestamp') or ''}"
            for row in agent_task_rows(sub.agent_id)
        ]
    if section_type == "artifacts":
        return [
            f"- {row.get('uri') or row.get('path') or row.get('artifact_id')} · {row.get('type') or '-'}"
            for row in agent_artifact_rows(sub.agent_id)
        ]
    if section_type == "approvals":
        return [
            f"- {row.get('approval_id') or '-'} · {row.get('type') or '-'} · {row.get('summary') or '-'}"
            for row in agent_approval_rows(state, sub.agent_id)
        ]
    if section_type == "memory":
        memory = memory_summary_for_subagent(sub)
        return memory.splitlines()[:20] if memory else []
    if section_type == "markdown":
        markdown = bounded_dashboard_text(section.get("markdown") or dashboard_spec_for_subagent(sub).get("markdown"), 3000)
        return markdown.splitlines()[:80] if markdown else []
    return []


def subagent_home_lines_uncached(state: State, sub: SubAgentRuntime, width: int) -> list[RenderLine]:
    role = normalized_subagent_role(sub.role)
    active_tasks = agent_task_rows(sub.agent_id, include_terminal=False, limit=20)
    schedule_rows = agent_schedule_rows(sub.agent_id)
    approval_rows = agent_approval_rows(state, sub.agent_id)
    lines = [
        RenderLine(f"{sub.name} 主页", cp(7) | curses.A_BOLD),
    ]
    append_status_card(
        lines,
        title=f"{sub.name} / {role}",
        summary=dashboard_status_for_subagent(sub),
        metrics=[
            ("状态", sub.status),
            ("生命周期", "persistent" if sub.persistent else "temporary"),
            ("任务队列", str(len(sub.task_queue))),
            ("聊天队列", str(len(sub.chat_queue))),
            ("未终态任务", str(len(active_tasks))),
            ("待审批", str(len(approval_rows))),
        ],
        details=[
            ("ID", sub.agent_id),
            ("安全上下文", sub.security_context),
            ("默认模型", sub.default_model or "-"),
            ("专属技能", format_subagent_skill_refs(sub.skill_refs, empty="-")),
            ("活跃任务", sub.active_bus_task_id or "-"),
            ("定时任务", str(len(schedule_rows))),
            ("最近更新", rel_age(sub.updated_at)),
        ],
        width=width,
    )
    if not sub.persistent:
        append_home_section(lines, "临时代理", ["- 临时会话代理不持久化主页；使用 /chat 继续聊天。"], width)
        return lines
    sections = dashboard_sections_for_subagent(sub)
    for section in sections:
        title = str(section.get("title") or section.get("type") or "section")
        body = subagent_home_section_body(state, sub, section, width=width)
        append_home_section(lines, title, body, width)
    if not any(str(section.get("type") or "") == "scheduled_reports" for section in sections):
        append_home_section(
            lines,
            "定时汇报",
            subagent_home_section_body(state, sub, {"type": "scheduled_reports"}, width=width),
            width,
        )
    append_home_action_panel(lines, "详情入口", [
        ("继续对话", "/chat"),
        ("代理设置", "/agent settings"),
        ("返回主页", "/agent-dashboard <agent>"),
    ], width)
    return lines


def main_home_lines(state: State, width: int) -> list[RenderLine]:
    return main_home_lines_uncached(state, width)


def subagent_home_lines(state: State, sub: SubAgentRuntime, width: int) -> list[RenderLine]:
    return subagent_home_lines_uncached(state, sub, width)


def home_registry_signature() -> tuple[tuple[int, int], ...]:
    return (
        jsonl_file_signature(AGENT_TASK_LEDGER_PATH),
        jsonl_file_signature(AGENT_PROGRESS_LEDGER_PATH),
        jsonl_file_signature(AGENT_APPROVALS_PATH),
        jsonl_file_signature(AGENT_ARTIFACT_INDEX_PATH),
        jsonl_file_signature(AGENT_SCHEDULES_PATH),
        jsonl_file_signature(AGENT_SCHEDULE_RUNS_PATH),
    )


def main_history_home_signature(limit: int = 12) -> tuple[Any, ...]:
    rows: list[tuple[str, int, int]] = []
    try:
        paths = glob.glob(os.path.join(MODEL_RESPONSES_DIR, "model_responses*.txt"))
    except OSError:
        paths = []
    for path in paths:
        if not is_normal_session_log_path(path):
            continue
        try:
            stat = os.stat(path)
        except OSError:
            continue
        rows.append((os.path.basename(path), int(stat.st_mtime_ns), int(stat.st_size)))
    rows.sort(key=lambda item: (item[1], item[0]), reverse=True)
    names_path = str(getattr(session_names, "_REG_PATH", "") or "") if session_names is not None else ""
    return (
        jsonl_file_signature(SESSION_META_PATH),
        jsonl_file_signature(names_path) if names_path else (0, 0),
        tuple(rows[:limit]),
    )


def subagent_chat_history_home_signature(state: State, sub: SubAgentRuntime, limit: int = 12) -> tuple[Any, ...]:
    if sub.security_context == "secret":
        if state is None or not state.secret_vault.unlocked:
            return ("secret-locked",)
        return ("secret", secret_file_signature(SECRET_SUBAGENT_CHAT_KIND, "*.secret")[:limit])
    history_rows: list[tuple[str, float, int]] = []
    for key, meta in load_session_meta_registry().items():
        if not isinstance(meta, dict) or not subagent_chat_history_meta_matches(meta, sub):
            continue
        history_rows.append((
            str(meta.get("subagent_chat_session_id") or key),
            session_meta_epoch(meta.get("updated_at") or meta.get("last_user_at")),
            int(meta.get("message_count") or 0),
        ))
    history_rows.sort(key=lambda item: (item[1], item[0]), reverse=True)
    legacy_rows: list[tuple[str, int, int]] = []
    try:
        paths = glob.glob(os.path.join(subagent_sessions_dir(sub), "*.json"))
    except OSError:
        paths = []
    for path in paths:
        try:
            stat = os.stat(path)
        except OSError:
            continue
        legacy_rows.append((os.path.basename(path), int(stat.st_mtime_ns), int(stat.st_size)))
    legacy_rows.sort(key=lambda item: (item[1], item[0]), reverse=True)
    return (
        jsonl_file_signature(SESSION_META_PATH),
        tuple(history_rows[:limit]),
        tuple(legacy_rows[:limit]),
    )


def home_line_cache_key(state: State, width: int) -> tuple[Any, ...]:
    selected = str(state.selected_session or "")
    registry_signature = home_registry_signature()
    sub = selected_home_subagent(state)
    if sub is not None:
        scope_signature: tuple[Any, ...] = (
            "sub",
            sub.agent_id,
            sub.name,
            sub.role,
            sub.status,
            sub.default_model,
            sub.security_context,
            sub.persistent,
            len(sub.task_queue),
            len(sub.chat_queue),
            sub.active_bus_task_id,
            sub.chat_session_id,
            sub.chat_title,
            len(sub.messages),
            round(float(sub.updated_at or 0.0), 3),
            dashboard_cache_signature(sub.dashboard),
            subagent_chat_history_home_signature(state, sub) if dashboard_sections_include_sessions(dashboard_sections_for_subagent(sub)) else (),
        )
    elif is_scheduled_reports_session_key(state.selected_session):
        scope_signature = (
            "scheduled_reports",
            state.status,
        )
    else:
        try:
            model_name = str(state.agent.get_llm_name(model=True))
        except Exception:
            model_name = agent_current_backend_name(state.agent) or ""
        scope_signature = (
            "main",
            state.status,
            state.current_title,
            len(state.background_sessions),
            model_name,
            dashboard_cache_signature(state.main_dashboard),
            main_history_home_signature() if dashboard_sections_include_sessions(dashboard_sections_for_main(state)) else (),
        )
    return (
        selected,
        int(width),
        bool(state.secret_vault.unlocked),
        registry_signature,
        scope_signature,
    )


def home_lines(state: State, width: int) -> list[RenderLine]:
    cache_key = home_line_cache_key(state, width)
    now = time.time()
    if (
        state.home_line_cache
        and state.home_line_cache_key == cache_key
        and now - state.home_line_cache_loaded_at < HOME_LINE_CACHE_TTL_SECONDS
    ):
        return list(state.home_line_cache)
    lines = home_lines_uncached(state, width)
    state.home_line_cache_key = home_line_cache_key(state, width)
    state.home_line_cache = list(lines)
    state.home_line_cache_loaded_at = now
    return lines


def home_lines_uncached(state: State, width: int) -> list[RenderLine]:
    sub = selected_home_subagent(state)
    if sub is not None:
        return subagent_home_lines_uncached(state, sub, width)
    if is_scheduled_reports_session_key(state.selected_session):
        return scheduled_reports_home_lines_uncached(state, width)
    if is_main_home_session_key(state.selected_session):
        return main_home_lines_uncached(state, width)
    return []


def prune_message_block_cache(state: State, live_keys: set[tuple[Any, ...]], max_entries: int = 1200) -> None:
    if not state.message_block_cache:
        return
    stale = [key for key in state.message_block_cache if key not in live_keys]
    for key in stale:
        state.message_block_cache.pop(key, None)
    limit = max(max_entries, len(live_keys) + 100)
    overflow = len(state.message_block_cache) - limit
    if overflow > 0:
        for key in list(state.message_block_cache)[:overflow]:
            state.message_block_cache.pop(key, None)


def message_lines_cached(state: State, width: int) -> list[RenderLine]:
    messages = display_messages(state)
    # Message cache invalidation is driven by message_version/content changes.
    # The running spinner must not force long assistant responses through the
    # markdown/process renderer on every animation tick.
    frame = 0
    scope = display_scope_key(state)
    assistant_label = "AI"
    render_signature = (state.message_version, message_cache_signature(messages))
    key = (
        render_signature,
        scope,
        assistant_label,
        width,
        state.fold_process,
        state.markdown,
        tuple(sorted(state.expanded_process_groups)),
        tuple(sorted(state.expanded_process_turns)),
        tuple(sorted(state.expanded_subagent_meta)),
        frame,
    )
    if key != state.line_cache_key:
        state.line_cache = message_lines_from_cache(
            state,
            messages,
            width,
            state.fold_process,
            state.markdown,
            frame,
            process_scope=scope,
            expanded_groups=state.expanded_process_groups,
            expanded_turns=state.expanded_process_turns,
            expanded_subagent_meta=state.expanded_subagent_meta,
            assistant_label=assistant_label,
        )
        state.line_cache_key = key
    return state.line_cache


